class Solution {
  public boolean containsNearbyDuplicate(int[] nums, int k) {
    // Create a HashSet to store the elements within the window
    Set<Integer> window = new HashSet<>();

    // Iterate over the array
    for (int i = 0; i < nums.length; i++) {
      // If the window contains the current element, return true
      if (window.contains(nums[i])) {
        return true;
      }

      // Add the current element to the window
      window.add(nums[i]);

      // If the window size exceeds k, remove the oldest element
      if (window.size() > k) {
        window.remove(nums[i - k]);
      }
    }

    // If no duplicates are found, return false
    return false;
  }
}

class Solution {
  public int lengthOfLongestSubstring(String s) {
    // Create a HashMap to store the character frequencies
    Map<Character, Integer> freq = new HashMap<>();

    // Initialize the window boundaries
    int left = 0, maxLen = 0;

    // Iterate over the string
    for (int right = 0; right < s.length(); right++) {
      // Increment the frequency of the current character
      freq.put(s.charAt(right), freq.getOrDefault(s.charAt(right), 0) + 1);

      // While the window contains duplicate characters, shrink the window
      while (freq.get(s.charAt(right)) > 1) {
        freq.put(s.charAt(left), freq.get(s.charAt(left)) - 1);
        left++;
      }

      // Update the maximum length
      maxLen = Math.max(maxLen, right - left + 1);
    }

    // Return the maximum length
    return maxLen;
  }
}

class Solution {
  public String minWindow(String s, String t) {
    // Create a HashMap to store the character frequencies of the target string
    Map<Character, Integer> tFreq = new HashMap<>();

    // Initialize the window boundaries
    int left = 0, minLen = Integer.MAX_VALUE;
    String minWindow = "";

    // Initialize the count of characters in the target string
    int count = 0;

    // Iterate over the string
    for (int right = 0; right < s.length(); right++) {
      // If the current character is in the target string, increment the count
      if (tFreq.containsKey(s.charAt(right))) {
        tFreq.put(s.charAt(right), tFreq.get(s.charAt(right)) - 1);
        if (tFreq.get(s.charAt(right)) >= 0) {
          count++;
        }
      }

      // While the window contains all characters of the target string, try to shrink the window
      while (count == t.length()) {
        // Update the minimum length and window
        if (right - left + 1 < minLen) {
          minLen = right - left + 1;
          minWindow = s.substring(left, right + 1);
        }

        // If the character at the left boundary is in the target string, decrement the count
        if (tFreq.containsKey(s.charAt(left))) {
          tFreq.put(s.charAt(left), tFreq.get(s.charAt(left)) + 1);
          if (tFreq.get(s.charAt(left)) > 0) {
            count--;
          }
        }

        // Move the left boundary to the right
        left++;
      }
    }

    // Return the minimum window
    return minWindow;
  }
}

class Solution {
  public int[] maxSlidingWindow(int[] nums, int k) {
    // Create a deque to store the indices of the elements in the window
    Deque<Integer> deque = new ArrayDeque<>();

    // Create an array to store the maximum values
    int[] maxValues = new int[nums.length - k + 1];

    // Iterate over the array
    for (int i = 0; i < nums.length; i++) {
      // Remove the elements from the back of the deque that are out of the window
      while (!deque.isEmpty() && deque.peekFirst() < i - k + 1) {
        deque.pollFirst();
      }

      // Remove the elements from the front of the deque that are smaller than the current element
      while (!deque.isEmpty() && nums[deque.peekLast()] < nums[i]) {
        deque.pollLast();
      }

      // Add the current element to the deque
      deque.offerLast(i);

      // If the window is full, add the maximum value to the result array
      if (i >= k - 1) {
        maxValues[i - k + 1] = nums[deque.peekFirst()];
      }
    }

    // Return the maximum values
    return maxValues;
  }
}

