      // Update minimum price
      if (price < minPrice) {
        minPrice = price;
      }

      // Update maximum profit
      if (price - minPrice > maxProfit) {
        maxProfit = price - minPrice;
      }
    }

    // Return maximum profit
    return maxProfit;
  }
}

public class Solution {
  public int lengthOfLongestSubstring(String s) {
    // Initialize variables
    int maxLength = 0;
    int windowStart = 0;
    Set<Character> uniqueChars = new HashSet<>();

    // Iterate through the string
    for (int windowEnd = 0; windowEnd < s.length(); windowEnd++) {
      // Add character to the set of unique characters
      while (uniqueChars.contains(s.charAt(windowEnd))) {
        // Shrink the window from the left
        uniqueChars.remove(s.charAt(windowStart));
        windowStart++;
      }
      uniqueChars.add(s.charAt(windowEnd));

      // Update the longest substring length
      maxLength = Math.max(maxLength, windowEnd - windowStart + 1);
    }
    return maxLength;
  }
}

public class Solution {
  public ListNode reverseList(ListNode head) {
    // Initialize variables
    ListNode prev = null;
    ListNode curr = head;
    ListNode next = null;

    // Iterate through the list
    while (curr != null) {
      // Store the next node
      next = curr.next;

      // Reverse 'next' pointer
      curr.next = prev;

      // Update previous and current nodes
      prev = curr;
      curr = next;
    }
    return prev;
  }
}

public class Solution {
  public ListNode mergeTwoLists(ListNode l1, ListNode l2) {
    // Initialize variables
    ListNode dummy = new ListNode(0);
    ListNode curr = dummy;

    // Iterate through both lists
    while (l1 != null && l2 != null) {
      // Compare node values
      if (l1.val < l2.val) {
        curr.next = l1;
        l1 = l1.next;
      } else {
        curr.next = l2;
        l2 = l2.next;
      }
      curr = curr.next;
    }

    // Handle remaining nodes
    if (l1 != null) {
      curr.next = l1;
    } else {
      curr.next = l2;
    }
    return dummy.next;
  }
}

public class Solution {
  public boolean isValid(String s) {
    // Initialize stack
    Stack<Character> stack = new Stack<>();

    // Iterate through string
    for (char c : s.toCharArray()) {
      // Push opening parentheses onto the stack
      if (c == '(' || c == '[' || c == '{') {
        stack.push(c);
      } else {
        // Pop matching opening parenthesis from the stack
        if (stack.isEmpty()) {
          return false;
        }
        char opening = stack.pop();
        if ((c == ')' && opening != '(') || (c == ']' && opening != '[') || (c == '}' && opening != '{')) {
          return false;
        }
      }
    }

    // Check for unmatched parentheses
    return stack.isEmpty();
  }
}

public class Solution {
  public boolean hasCycle(ListNode head) {
    // Initialize pointers
    ListNode slow = head;
    ListNode fast = head;

    // Iterate through list
    while (fast != null && fast.next != null) {
      // Move slow pointer one step at a time
      slow = slow.next;

      // Move fast pointer two steps at a time
      fast = fast.next.next;

      // Detect cycle
      if (slow == fast) {
        return true;
      }
    }

    // Handle no cycle
    return false;
  }
}

public class Solution {
  public TreeNode lowestCommonAncestor(TreeNode root, TreeNode p, TreeNode q) {
    // Base case: if the tree is empty, return null
    if (root == null) return null;

    // If the current node's value is greater than both p and q, recurse on the left subtree
    if (root.val > p.val && root.val > q.val) {
      return lowestCommonAncestor(root.left, p, q);
    }

    // If the current node's value is less than both p and q, recurse on the right subtree
    if (root.val < p.val && root.val < q.val) {
      return lowestCommonAncestor(root.right, p, q);
    }

    // If the current node's value is between p and q, return the current node
    return root;
  }
}

public class Trie {
  private class TrieNode {
    Map<Character, TrieNode> children;
    boolean isEndOfWord;

    public TrieNode() {
      children = new HashMap<>();
      isEndOfWord = false;
    }
  }

  private TrieNode root;

  public Trie() {
    root = new TrieNode();
  }

  public void insert(String word) {
    TrieNode node = root;
    for (char c : word.toCharArray()) {
      if (!node.children.containsKey(c)) {
        node.children.put(c, new TrieNode());
      }
      node = node.children.get(c);
    }
    node.isEndOfWord = true;
  }

  public boolean search(String word) {
    TrieNode node = root;
    for (char c : word.toCharArray()) {
      if (!node.children.containsKey(c)) {
        return false;
      }
      node = node.children.get(c);
    }
    return node.isEndOfWord;
  }

  public boolean startsWith(String prefix) {
    TrieNode node = root;
    for (char c : prefix.toCharArray()) {
      if (!node.children.containsKey(c)) {
        return false;
      }
      node = node.children.get(c);
    }
    return true;
  }
}

public class Solution {
  public int[] maxSlidingWindow(int[] nums, int k) {
    if (nums == null || k == 0) return new int[0];

    int[] result = new int[nums.length - k + 1];
    Deque<Integer> deque = new ArrayDeque<>();

    for (int i = 0; i < nums.length; i++) {
      // Remove elements from the back of the deque that are out of the window
      while (!deque.isEmpty() && deque.peekFirst() < i - k + 1) {
        deque.pollFirst();
      }

      // Remove elements from the front of the deque that are smaller than the current element
      while (!deque.isEmpty() && nums[deque.peekLast()] < nums[i]) {
        deque.pollLast();
      }

      // Add the current element to the deque
      deque.offerLast(i);

      // Add the maximum element to the result array
      if (i >= k - 1) {
        result[i - k + 1] = nums[deque.peekFirst()];
      }
    }

    return result;
  }
}

public class Solution {
  public int largestRectangleArea(int[] heights) {
    if (heights == null || heights.length == 0) return 0;

    int[] heightsWithDummy = new int[heights.length + 1];
    System.arraycopy(heights, 0, heightsWithDummy, 0, heights.length);
    heightsWithDummy[heights.length] = 0;

    int[] stack = new int[heights.length + 1];
    int top = -1;
    int maxArea = 0;

    for (int i = 0; i < heightsWithDummy.length; i++) {
      while (top >= 0 && heightsWithDummy[stack[top]] > heightsWithDummy[i]) {
        int height = heightsWithDummy[stack[top--]];
        int width = top < 0 ? i : i - stack[top] - 1;
        maxArea = Math.max(maxArea, height * width);
      }
      stack[++top] = i;
    }

    return maxArea;
  }
}

public class Solution {
  public int search(int[] nums, int target) {
    if (nums == null || nums.length == 0) return -1;

    int low = 0;
    int high = nums.length - 1;

    while (low <= high) {
      int mid = low + (high - low) / 2;

      if (nums[mid] == target) return mid;

      if (nums[low] <= nums[mid]) {
        // Left half is sorted
        if (nums[low] <= target && target < nums[mid]) {
          high = mid - 1;
        } else {
          low = mid + 1;
        }
      } else {
        // Right half is sorted
        if (nums[mid] < target && target <= nums[high]) {
          low = mid + 1;
        } else {
          high = mid - 1;
        }
      }
    }

    return -1;
  }
}

public class Solution {
  public int maxDepth(TreeNode root) {
    // Base case: empty tree
    if (root == null) {
      return 0;
    }
    // Recursively calculate depth
    int leftDepth = maxDepth(root.left);
    int rightDepth = maxDepth(root.right);
    // Add 1 for current node
    return Math.max(leftDepth, rightDepth) + 1;
  }
}

public class Solution {
  public List<List<Integer>> levelOrder(TreeNode root) {
    List<List<Integer>> result = new ArrayList<>();
    if (root == null) {
      return result;
    }
    Queue<TreeNode> queue = new LinkedList<>();
    queue.add(root);
    while (!queue.isEmpty()) {
      List<Integer> level = new ArrayList<>();
      int size = queue.size();
      for (int i = 0; i < size; i++) {
        TreeNode node = queue.poll();
        level.add(node.val);
        if (node.left != null) {
          queue.add(node.left);
        }
        if (node.right != null) {
          queue.add(node.right);
        }
      }
      result.add(level);
    }
    return result;
  }
}

public class Solution {
  public List<List<Integer>> combinationSum(int[] candidates, int target) {
    List<List<Integer>> result = new ArrayList<>();
    backtrack(result, new ArrayList<>(), candidates, target, 0);
    return result;
  }
  private void backtrack(List<List<Integer>> result, List<Integer> tempList, int[] nums, int remain, int start) {
    if (remain < 0) return;
    else if (remain == 0) result.add(new ArrayList<>(tempList));
    else {
      for (int i = start; i < nums.length; i++) {
        tempList.add(nums[i]);
        backtrack(result, tempList, nums, remain - nums[i], i);
        tempList.remove(tempList.size() - 1);
      }
    }
  }
}

public class Solution {
  public List<List<Integer>> permute(int[] nums) {
    List<List<Integer>> result = new ArrayList<>();
    backtrack(result, new ArrayList<>(), nums);
    return result;
  }
  private void backtrack(List<List<Integer>> result, List<Integer> tempList, int[] nums) {
    if (tempList.size() == nums.length) {
      result.add(new ArrayList<>(tempList));
    } else {
      for (int num : nums) {
        if (tempList.contains(num)) continue;
        tempList.add(num);
        backtrack(result, tempList, nums);
        tempList.remove(tempList.size() - 1);
      }
    }
  }
}

public class Solution {
  public int numIslands(char[][] grid) {
    if (grid == null || grid.length == 0) {
      return 0;
    }
    int count = 0;
    for (int i = 0; i < grid.length; i++) {
      for (int j = 0; j < grid[0].length; j++) {
        if (grid[i][j] == '1') {
          dfs(grid, i, j);
          count++;
        }
      }
    }
    return count;
  }
  private void dfs(char[][] grid, int i, int j) {
    if (i < 0 || j < 0 || i >= grid.length || j >= grid[0].length || grid[i][j] != '1') {
      return;
    }
    grid[i][j] = '0';
    dfs(grid, i - 1, j);
    dfs(grid, i + 1, j);
    dfs(grid, i, j - 1);
    dfs(grid, i, j + 1);
  }
}

public class CoinChange {
  public int coinChange(int[] coins, int amount) {
    // Initialize DP table
    int[] dp = new int[amount + 1];
    Arrays.fill(dp, Integer.MAX_VALUE);
    dp[0] = 0;

    // Fill DP table
    for (int coin : coins) {
      for (int i = coin; i <= amount; i++) {
        if (dp[i - coin] != Integer.MAX_VALUE) {
          dp[i] = Math.min(dp[i], dp[i - coin] + 1);
        }
      }
    }

    // Handle edge cases
    if (dp[amount] == Integer.MAX_VALUE) {
      return -1;
    }

    // Return minimum coins
    return dp[amount];
  }
}

public class MergeIntervals {
  public int[][] merge(int[][] intervals) {
    // Sort intervals
    Arrays.sort(intervals, (a, b) -> a[0] - b[0]);

    // Initialize merged intervals
    List<int[]> merged = new ArrayList<>();

    // Merge overlapping intervals
    for (int[] interval : intervals) {
      if (merged.isEmpty() || merged.get(merged.size() - 1)[1] < interval[0]) {
        merged.add(interval);
      } else {
        merged.get(merged.size() - 1)[1] = Math.max(merged.get(merged.size() - 1)[1], interval[1]);
      }
    }

    // Return merged intervals
    return merged.toArray(new int[0][]);
  }
}

public class ValidateBinarySearchTree {
  public boolean isValidBST(TreeNode root) {
    // Define valid range
    return isValidBSTHelper(root, Long.MIN_VALUE, Long.MAX_VALUE);
  }

  private boolean isValidBSTHelper(TreeNode node, long minVal, long maxVal) {
    // Check node values
    if (node == null) {
      return true;
    }

    if (node.val <= minVal || node.val >= maxVal) {
      return false;
    }

    // Update valid range for child nodes
    return isValidBSTHelper(node.left, minVal, node.val) && isValidBSTHelper(node.right, node.val, maxVal);
  }
}

public class CloneGraph {
  public Node cloneGraph(Node node) {
    // Create clone map
    Map<Node, Node> cloneMap = new HashMap<>();

    // Clone nodes
    return cloneGraphHelper(node, cloneMap);
  }

  private Node cloneGraphHelper(Node node, Map<Node, Node> cloneMap) {
    // Clone nodes
    if (node == null) {
      return null;
    }

    if (cloneMap.containsKey(node)) {
      return cloneMap.get(node);
    }

    // Clone edges
    Node clone = new Node(node.val);
    cloneMap.put(node, clone);

    for (Node neighbor : node.neighbors) {
      clone.neighbors.add(cloneGraphHelper(neighbor, cloneMap));
    }

    return clone;
  }
}

public class CourseSchedule {
  public boolean canFinish(int numCourses, int[][] prerequisites) {
    // Create graph
    List<List<Integer>> graph = new ArrayList<>();
    for (int i = 0; i < numCourses; i++) {
      graph.add(new ArrayList<>());
    }

    // Add edges to graph
    for (int[] prerequisite : prerequisites) {
      graph.get(prerequisite[1]).add(prerequisite[0]);
    }

    // Perform topological sorting
    int[] visited = new int[numCourses];
    for (int i = 0; i < numCourses; i++) {
      if (visited[i] == 0 && !canFinishHelper(graph, visited, i)) {
        return false;
      }
    }

    return true;
  }

  private boolean canFinishHelper(List<List<Integer>> graph, int[] visited, int course) {
    // Detect cycles
    if (visited[course] == 1) {
      return false;
    }

    if (visited[course] == 2) {
      return true;
    }

    visited[course] = 1;

    for (int neighbor : graph.get(course)) {
      if (!canFinishHelper(graph, visited, neighbor)) {
        return false;
      }
    }

    visited[course] = 2;
    return true;
  }
}

public class Solution {
  public int uniquePaths(int m, int n) {
    // Initialize the 2-D array
    int[][] dp = new int[m][n];
    // Fill in the first row and column
    for (int i = 0; i < m; i++) {
      dp[i][0] = 1;
    }
    for (int j = 0; j < n; j++) {
      dp[0][j] = 1;
    }
    // Fill in the rest of the 2-D array
    for (int i = 1; i < m; i++) {
      for (int j = 1; j < n; j++) {
        dp[i][j] = dp[i-1][j] + dp[i][j-1];
      }
    }
    // Return the result
    return dp[m-1][n-1];
  }
}

public class Solution {
  public int minDistance(String word1, String word2) {
    // Initialize the 2-D array
    int[][] dp = new int[word1.length() + 1][word2.length() + 1];
    // Fill in the first row and column
    for (int i = 0; i <= word1.length(); i++) {
      dp[i][0] = i;
    }
    for (int j = 0; j <= word2.length(); j++) {
      dp[0][j] = j;
    }
    // Fill in the rest of the 2-D array
    for (int i = 1; i <= word1.length(); i++) {
      for (int j = 1; j <= word2.length(); j++) {
        if (word1.charAt(i-1) == word2.charAt(j-1)) {
          dp[i][j] = dp[i-1][j-1];
        } else {
          dp[i][j] = 1 + Math.min(Math.min(dp[i-1][j], dp[i][j-1]), dp[i-1][j-1]);
        }
      }
    }
    // Return the result
    return dp[word1.length()][word2.length()];
  }
}

public class Codec {
  public String serialize(TreeNode root) {
    // Serialize the binary tree using a pre-order traversal
    StringBuilder sb = new StringBuilder();
    serializeHelper(root, sb);
    return sb.toString();
  }

  private void serializeHelper(TreeNode node, StringBuilder sb) {
    if (node == null) {
      sb.append("#,");
    } else {
      sb.append(node.val + ",");
      serializeHelper(node.left, sb);
      serializeHelper(node.right, sb);
    }
  }

  public TreeNode deserialize(String data) {
    // Deserialize the string representation into a binary tree
    String[] nodes = data.split(",");
    int[] index = new int[] {0};
    return deserializeHelper(nodes, index);
  }

  private TreeNode deserializeHelper(String[] nodes, int[] index) {
    if (index[0] >= nodes.length || nodes[index[0]].equals("#")) {
      index[0]++;
      return null;
    }
    TreeNode node = new TreeNode(Integer.parseInt(nodes[index[0]++]));
    node.left = deserializeHelper(nodes, index);
    node.right = deserializeHelper(nodes, index);
    return node;
  }
}

public class MedianFinder {
  private PriorityQueue<Integer> maxHeap;
  private PriorityQueue<Integer> minHeap;

  public MedianFinder() {
    // Initialize the heaps
    maxHeap = new PriorityQueue<>((a, b) -> b - a);
    minHeap = new PriorityQueue<>();
  }

  public void addNum(int num) {
    // Insert the number into the correct heap
    if (maxHeap.isEmpty() || num <= maxHeap.peek()) {
      maxHeap.offer(num);
    } else {
      minHeap.offer(num);
    }
    // Balance the heaps
    if (maxHeap.size() > minHeap.size() + 1) {
      minHeap.offer(maxHeap.poll());
    } else if (minHeap.size() > maxHeap.size()) {
      maxHeap.offer(minHeap.poll());
    }
  }

  public double findMedian() {
    // Calculate the median
    if (maxHeap.size() > minHeap.size()) {
      return (double) maxHeap.peek();
    } else {
      return (maxHeap.peek() + minHeap.peek()) / 2.0;
    }
  }
}

