public List<List<String>> groupAnagrams(String[] strs) {
  // Create a hashmap to store anagrams
  Map<String, List<String>> anagramMap = new HashMap<>();

  // Iterate over each string in the input array
  for (String str : strs) {
    // Sort the characters in the string to create a normalized key
    char[] sortedChars = str.toCharArray();
    Arrays.sort(sortedChars);
    String sortedStr = new String(sortedChars);

    // Store the string in the hashmap based on its sorted characters
    if (!anagramMap.containsKey(sortedStr)) {
      anagramMap.put(sortedStr, new ArrayList<>());
    }
    anagramMap.get(sortedStr).add(str);
  }

  // Return the values of the hashmap, which represent the groups of anagrams
  return new ArrayList<>(anagramMap.values());
}

public boolean isPalindrome(String s) {
  // Initialize two pointers, one at the beginning and one at the end of the string
  int left = 0;
  int right = s.length() - 1;

  // Compare characters, ignoring non-alphanumeric characters and considering the string as case-insensitive
  while (left < right) {
    if (!Character.isLetterOrDigit(s.charAt(left))) {
      left++;
    } else if (!Character.isLetterOrDigit(s.charAt(right))) {
      right--;
    } else {
      if (Character.toLowerCase(s.charAt(left)) != Character.toLowerCase(s.charAt(right))) {
        return false;
      }
      left++;
      right--;
    }
  }

  // Return true if the string is a palindrome
  return true;
}

public int maxArea(int[] height) {
  // Initialize two pointers, one at the beginning and one at the end of the array
  int left = 0;
  int right = height.length - 1;
  int maxArea = 0;

  // Calculate the area between the two pointers and update the maximum area
  while (left < right) {
    int area = Math.min(height[left], height[right]) * (right - left);
    maxArea = Math.max(maxArea, area);

    // Move the pointer with the smaller height towards the other pointer
    if (height[left] < height[right]) {
      left++;
    } else {
      right--;
    }
  }

  // Return the maximum area found
  return maxArea;
}

public int search(int[] nums, int target) {
  // Initialize the search interval to the entire array
  int left = 0;
  int right = nums.length - 1;

  // Repeat the search process until the target value is found or the search interval is empty
  while (left <= right) {
    // Calculate the mid index of the search interval
    int mid = left + (right - left) / 2;

    // Compare the target value with the value at the mid index
    if (nums[mid] == target) {
      // Return the index of the target value if found
      return mid;
    } else if (nums[mid] < target) {
      // Update the search interval to the half that contains the target value
      left = mid + 1;
    } else {
      // Update the search interval to the half that contains the target value
      right = mid - 1;
    }
  }

  // Return a special value to indicate that the target value is not in the array
  return -1;
}

public int climbStairs(int n) {
  // Initialize the base cases
  if (n == 1) {
    return 1;
  } else if (n == 2) {
    return 2;
  }

  // Create a DP array to store the number of ways to reach each step
  int[] dp = new int[n + 1];
  dp[1] = 1;
  dp[2] = 2;

  // Fill the DP array using a bottom-up approach
  for (int i = 3; i <= n; i++) {
    dp[i] = dp[i - 1] + dp[i - 2];
  }

  // Return the number of ways to reach the top step
  return dp[n];
}

public class Solution {
  public TreeNode invertTree(TreeNode root) {
    // Base case: if the tree is empty, return null
    if (root == null) return null;

    // Swap child nodes
    TreeNode temp = root.left;
    root.left = root.right;
    root.right = temp;

    // Recursively traverse the tree
    root.left = invertTree(root.left);
    root.right = invertTree(root.right);

    // Return the inverted tree
    return root;
  }
}

public class Solution {
  public String minWindow(String s, String t) {
    // Create frequency count maps
    Map<Character, Integer> tCount = new HashMap<>();
    for (char c : t.toCharArray()) {
      tCount.put(c, tCount.getOrDefault(c, 0) + 1);
    }

    // Initialize the window
    int left = 0, minLen = Integer.MAX_VALUE;
    String minWindow = "";
    Map<Character, Integer> windowCount = new HashMap<>();

    // Expand the window
    for (int right = 0; right < s.length(); right++) {
      char c = s.charAt(right);
      windowCount.put(c, windowCount.getOrDefault(c, 0) + 1);

      // Shrink the window
      while (isValidWindow(windowCount, tCount)) {
        if (right - left + 1 < minLen) {
          minLen = right - left + 1;
          minWindow = s.substring(left, right + 1);
        }
        char leftChar = s.charAt(left);
        windowCount.put(leftChar, windowCount.get(leftChar) - 1);
        if (windowCount.get(leftChar) == 0) {
          windowCount.remove(leftChar);
        }
        left++;
      }
    }

    return minWindow;
  }

  private boolean isValidWindow(Map<Character, Integer> windowCount, Map<Character, Integer> tCount) {
    for (char c : tCount.keySet()) {
      if (!windowCount.containsKey(c) || windowCount.get(c) < tCount.get(c)) {
        return false;
      }
    }
    return true;
  }
}

public class Solution {
  public int minEatingSpeed(int[] piles, int h) {
    // Define the search range
    int left = 1, right = Arrays.stream(piles).max().getAsInt();

    // Perform binary search
    while (left < right) {
      int mid = left + (right - left) / 2;
      if (canEatAll(piles, mid, h)) {
        right = mid;
      } else {
        left = mid + 1;
      }
    }

    // Return the minimum number of hours
    return left;
  }

  private boolean canEatAll(int[] piles, int k, int h) {
    int hours = 0;
    for (int pile : piles) {
      hours += (pile - 1) / k + 1;
    }
    return hours <= h;
  }
}

public class Solution {
  public List<List<Integer>> subsets(int[] nums) {
    // Define the base case
    List<List<Integer>> result = new ArrayList<>();
    backtrack(result, new ArrayList<>(), nums, 0);
    return result;
  }

  private void backtrack(List<List<Integer>> result, List<Integer> tempList, int[] nums, int start) {
    // Add the current subset to the result
    result.add(new ArrayList<>(tempList));

    // Generate all subsets
    for (int i = start; i < nums.length; i++) {
      // Add the current element to the subset
      tempList.add(nums[i]);
      backtrack(result, tempList, nums, i + 1);
      // Remove the current element from the subset
      tempList.remove(tempList.size() - 1);
    }
  }
}

public class Solution {
  public boolean exist(char[][] board, String word) {
    // Define the search directions
    int[][] directions = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};

    // Perform depth-first search
    for (int i = 0; i < board.length; i++) {
      for (int j = 0; j < board[0].length; j++) {
        if (board[i][j] == word.charAt(0)) {
          if (dfs(board, word, i, j, 0, directions)) {
            return true;
          }
        }
      }
    }

    // Return the result
    return false;
  }

  private boolean dfs(char[][] board, String word, int i, int j, int k, int[][] directions) {
    // Check if the word is found
    if (k == word.length()) {
      return true;
    }

    // Check if the cell is out of bounds
    if (i < 0 || i >= board.length || j < 0 || j >= board[0].length || board[i][j] != word.charAt(k)) {
      return false;
    }

    // Mark the cell as visited
    char temp = board[i][j];
    board[i][j] = '#';

    // Explore all possible directions
    for (int[] direction : directions) {
      if (dfs(board, word, i + direction[0], j + direction[1], k + 1, directions)) {
        return true;
      }
    }

    // Unmark the cell as visited
    board[i][j] = temp;

    // Return the result
    return false;
  }
}

public class Solution {
  public int longestCommonSubsequence(String text1, String text2) {
    int m = text1.length();
    int n = text2.length();
    int[][] dp = new int[m + 1][n + 1];
    // Fill in the 2-D array
    for (int i = 1; i <= m; i++) {
      for (int j = 1; j <= n; j++) {
        if (text1.charAt(i - 1) == text2.charAt(j - 1)) {
          dp[i][j] = dp[i - 1][j - 1] + 1;
        } else {
          dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]);
        }
      }
    }
    // Return the length of the longest common subsequence
    return dp[m][n];
  }
}

public class Solution {
  public int maxSubArray(int[] nums) {
    if (nums.length == 0) {
      return 0;
    }
    int maxSoFar = nums[0];
    int maxEndingHere = nums[0];
    for (int i = 1; i < nums.length; i++) {
      maxEndingHere = Math.max(nums[i], maxEndingHere + nums[i]);
      maxSoFar = Math.max(maxSoFar, maxEndingHere);
    }
    return maxSoFar;
  }
}

public class Solution {
