  }
}

public class Solution {
  public int reverseBits(int n) {
    int result = 0;
    for (int i = 0; i < 32; i++) {
      result = (result << 1) | (n & 1);
      n >>>= 1;
    }
    return result;
  }
}

public class LRUCache {
  // Initialize data structures
  private final int capacity;
  private final LinkedHashMap<Integer, Integer> cache;

  public LRUCache(int capacity) {
    this.capacity = capacity;
    this.cache = new LinkedHashMap<Integer, Integer>(capacity, 0.75f, true) {
      @Override
      protected boolean removeEldestEntry(Map.Entry eldest) {
        return size() > capacity;
      }
    };
  }

  public int get(int key) {
    // Implement get operation
    return cache.getOrDefault(key, -1);
  }

  public void put(int key, int value) {
    // Implement put operation
    cache.put(key, value);
  }
}

public class Solution {
  public ListNode mergeKLists(ListNode[] lists) {
    // Initialize min-heap
    PriorityQueue<ListNode> minHeap = new PriorityQueue<>((a, b) -> a.val - b.val);

    // Add initial elements to heap
    for (ListNode list : lists) {
      if (list != null) {
        minHeap.offer(list);
      }
    }

    // Initialize result list
    ListNode dummy = new ListNode(0);
    ListNode current = dummy;

    // Extract smallest element and add to result list
    while (!minHeap.isEmpty()) {
      ListNode smallest = minHeap.poll();
      current.next = smallest;
      current = current.next;

      // Add next element to heap
      if (smallest.next != null) {
        minHeap.offer(smallest.next);
      }
    }

    return dummy.next;
  }
}

public class Solution {
  public List<String> findWords(char[][] board, String[] words) {
    // Initialize Trie
    TrieNode root = new TrieNode();

    // Insert words into Trie
    for (String word : words) {
      TrieNode node = root;
      for (char c : word.toCharArray()) {
        if (node.children[c - 'a'] == null) {
          node.children[c - 'a'] = new TrieNode();
        }
        node = node.children[c - 'a'];
      }
      node.isWord = true;
    }

    // Initialize result list
    List<String> result = new ArrayList<>();

    // Perform depth-first search
    for (int i = 0; i < board.length; i++) {
      for (int j = 0; j < board[0].length; j++) {
        dfs(board, i, j, root, new StringBuilder(), result);
      }
    }

    return result;
  }

  private void dfs(char[][] board, int i, int j, TrieNode node, StringBuilder path, List<String> result) {
    // Check if word is in Trie
    if (node.isWord) {
      result.add(path.toString());
      node.isWord = false;
    }

    // Explore other paths
    char temp = board[i][j];
    board[i][j] = '#';
    for (int[] dir : directions) {
      int ni = i + dir[0];
      int nj = j + dir[1];
      if (ni >= 0 && ni < board.length && nj >= 0 && nj < board[0].length && board[ni][nj] != '#' && node.children[board[ni][nj] - 'a'] != null) {
        path.append(board[ni][nj]);
        dfs(board, ni, nj, node.children[board[ni][nj] - 'a'], path, result);
        path.deleteCharAt(path.length() - 1);
      }
    }
    board[i][j] = temp;
  }
}

public class Solution {
  public int lengthOfLIS(int[] nums) {
    // Initialize DP array
    int[] dp = new int[nums.length];

    // Fill up DP array
    for (int i = 0; i < nums.length; i++) {
      dp[i] = 1;
      for (int j = 0; j < i; j++) {
        if (nums[i] > nums[j]) {
          dp[i] = Math.max(dp[i], dp[j] + 1);
        }
      }
    }

    // Find maximum length
    int maxLength = 0;
    for (int length : dp) {
      maxLength = Math.max(maxLength, length);
    }

    return maxLength;
  }
}

public class Solution {
  public boolean canJump(int[] nums) {
    // Initialize variables
    int maxReachable = 0;
    int jumps = 0;

    // Iterate through array
    for (int i = 0; i < nums.length; i++) {
      // Check if end is reachable
      if (i > maxReachable) {
        return false;
      }

      // Update maximum reachable position
      maxReachable = Math.max(maxReachable, i + nums[i]);
    }

    return true;
  }
}

public class Solution {
  public int[][] insert(int[][] intervals, int[] newInterval) {
    // Initialize the result list
    List<int[]> result = new ArrayList<>();

    // Initialize the index
    int i = 0;

    // Add intervals that come before the new interval
    while (i < intervals.length && intervals[i][1] < newInterval[0]) {
      result.add(intervals[i]);
      i++;
    }

    // Merge overlapping intervals
    while (i < intervals.length && intervals[i][0] <= newInterval[1]) {
      newInterval[0] = Math.min(newInterval[0], intervals[i][0]);
      newInterval[1] = Math.max(newInterval[1], intervals[i][1]);
      i++;
    }

    // Add the merged interval
    result.add(newInterval);

    // Add remaining intervals
    while (i < intervals.length) {
      result.add(intervals[i]);
      i++;
    }

    // Return the result
    return result.toArray(new int[result.size()][]);
  }
}

public class Solution {
  public ListNode addTwoNumbers(ListNode l1, ListNode l2) {
    // Initialize the dummy node
    ListNode dummy = new ListNode(0);
    ListNode current = dummy;

    // Initialize the carry-over value
    int carry = 0;

    // Iterate through both linked lists
    while (l1 != null || l2 != null) {
      int sum = carry;
      if (l1 != null) {
        sum += l1.val;
        l1 = l1.next;
      }
      if (l2 != null) {
        sum += l2.val;
        l2 = l2.next;
      }

      // Create the new linked list
      current.next = new ListNode(sum % 10);
      current = current.next;

      // Update the carry-over value
      carry = sum / 10;
    }

    // Handle the remaining carry-over value
    if (carry > 0) {
      current.next = new ListNode(carry);
    }

    // Return the result
    return dummy.next;
  }
}

public class Solution {
  public int trap(int[] height) {
    // Initialize the two pointers
    int left = 0;
    int right = height.length - 1;

    // Initialize the maximum height of the bars
    int maxLeft = 0;
    int maxRight = 0;

    // Initialize the result
    int result = 0;

    // Iterate through the bars
    while (left <= right) {
      // Update the maximum height of the bars
      if (height[left] < height[right]) {
        if (height[left] >= maxLeft) {
          maxLeft = height[left];
        } else {
          result += maxLeft - height[left];
        }
        left++;
      } else {
        if (height[right] >= maxRight) {
          maxRight = height[right];
        } else {
          result += maxRight - height[right];
        }
        right--;
      }
    }

    // Return the result
    return result;
  }
}

public class MinStack {
  private Stack<Integer> stack;
  private Stack<Integer> minStack;

  public MinStack() {
    stack = new Stack<>();
    minStack = new Stack<>();
  }

  public void push(int x) {
    stack.push(x);
    if (minStack.isEmpty() || x <= minStack.peek()) {
      minStack.push(x);
    }
  }

  public void pop() {
    if (!stack.isEmpty()) {
      if (stack.peek().equals(minStack.peek())) {
        minStack.pop();
      }
      stack.pop();
    }
  }

  public int top() {
    return stack.peek();
  }

  public int getMin() {
    return minStack.peek();
  }
}

