public class MajorityElement {
  public int majorityElement(int[] nums) {
    // Initialize hash map to store element counts
    Map<Integer, Integer> countMap = new HashMap<>();

    // Count element occurrences
    for (int num : nums) {
      countMap.put(num, countMap.getOrDefault(num, 0) + 1);
    }

    // Find majority element
    for (int num : countMap.keySet()) {
      if (countMap.get(num) > nums.length / 2) {
        return num;
      }
    }

    // Handle edge cases
    return -1; // or throw exception
  }
}

public class LongestConsecutiveSequence {
  public int longestConsecutive(int[] nums) {
    // Initialize hash set to store elements
    Set<Integer> numSet = new HashSet<>();

    // Add elements to hash set
    for (int num : nums) {
      numSet.add(num);
    }

    // Initialize longest sequence length
    int longestSequence = 0;

    // Check for consecutive sequence
    for (int num : numSet) {
      if (!numSet.contains(num - 1)) {
        int currentNum = num;
        int currentSequence = 1;

        // Check for presence of next numbers in sequence
        while (numSet.contains(currentNum + 1)) {
          currentNum += 1;
          currentSequence += 1;
        }

        // Update longest sequence length
        longestSequence = Math.max(longestSequence, currentSequence);
      }
    }

    // Handle edge cases
    return longestSequence;
  }
}

public class Search2DMatrix {
  public boolean searchMatrix(int[][] matrix, int target) {
    // Initialize binary search
    int rows = matrix.length;
    int cols = matrix[0].length;
    int left = 0;
    int right = rows * cols - 1;

    // Perform binary search
    while (left <= right) {
      int mid = left + (right - left) / 2;
      int midVal = matrix[mid / cols][mid % cols];

      // Compare target element
      if (midVal == target) {
        return true;
      } else if (midVal < target) {
        left = mid + 1;
      } else {
        right = mid - 1;
      }
    }

    // Handle edge cases
    return false;
  }
}

public class MedianOfTwoSortedArrays {
  public double findMedianSortedArrays(int[] nums1, int[] nums2) {
    // Initialize binary search
    int totalLength = nums1.length + nums2.length;
    int startX = 0;
    int endX = nums1.length;

    // Perform binary search
    while (startX <= endX) {
      int partitionX = (startX + endX) / 2;
      int partitionY = (totalLength + 1) / 2 - partitionX;

      // Calculate elements at partition points
      int maxLeftX = (partitionX == 0) ? Integer.MIN_VALUE : nums1[partitionX - 1];
      int minRightX = (partitionX == nums1.length) ? Integer.MAX_VALUE : nums1[partitionX];
      int maxLeftY = (partitionY == 0) ? Integer.MIN_VALUE : nums2[partitionY - 1];
      int minRightY = (partitionY == nums2.length) ? Integer.MAX_VALUE : nums2[partitionY];

      // Compare elements at partition points
      if (maxLeftX <= minRightY && maxLeftY <= minRightX) {
        // Calculate median
        if (totalLength % 2 == 0) {
          return (Math.max(maxLeftX, maxLeftY) + Math.min(minRightX, minRightY)) / 2.0;
        } else {
          return (double) Math.max(maxLeftX, maxLeftY);
        }
      } else if (maxLeftX > minRightY) {
        endX = partitionX - 1;
      } else {
        startX = partitionX + 1;
      }
    }

    // Handle edge cases
    return 0.0;
  }
}

public class FindTheDuplicateNumber {
  public int findDuplicate(int[] nums) {
    // Initialize tortoise and hare
    int tortoise = nums[0];
    int hare = nums[0];

    // Detect cycle
    do {
      tortoise = nums[tortoise];
      hare = nums[nums[hare]];
    } while (tortoise != hare);

    // Find start of cycle
    tortoise = nums[0];
    while (tortoise != hare) {
      tortoise = nums[tortoise];
      hare = nums[hare];
    }

    // Return duplicate number
    return hare;
  }
}

public class Solution {
  public List<Integer> inorderTraversal(TreeNode root) {
    List<Integer> result = new ArrayList<>();
    // Recursive approach
    // traverse(root, result);
    // Iterative approach
    Stack<TreeNode> stack = new Stack<>();
    TreeNode current = root;
    while (current != null || !stack.isEmpty()) {
      while (current != null) {
        stack.push(current);
        current = current.left;
      }
      current = stack.pop();
      result.add(current.val);
      current = current.right;
    }
    return result;
  }
