public class Solution {
  private int maxDiameter = 0;
  public int diameterOfBinaryTree(TreeNode root) {
    maxDepth(root);
    return maxDiameter;
  }
  private int maxDepth(TreeNode node) {
    if (node == null) return 0;
    int leftDepth = maxDepth(node.left);
    int rightDepth = maxDepth(node.right);
    maxDiameter = Math.max(maxDiameter, leftDepth + rightDepth);
    return 1 + Math.max(leftDepth, rightDepth);
  }
}

public class Solution {
  public boolean isBalanced(TreeNode root) {
    return checkBalance(root) != -1;
  }
  private int checkBalance(TreeNode node) {
    if (node == null) return 0;
    int leftHeight = checkBalance(node.left);
    if (leftHeight == -1) return -1;
    int rightHeight = checkBalance(node.right);
    if (rightHeight == -1) return -1;
    if (Math.abs(leftHeight - rightHeight) > 1) return -1;
    return 1 + Math.max(leftHeight, rightHeight);
  }
}

public class Solution {
  public boolean isSameTree(TreeNode p, TreeNode q) {
    if (p == null && q == null) return true;
    if (p == null || q == null) return false;
    if (p.val != q.val) return false;
    return isSameTree(p.left, q.left) && isSameTree(p.right, q.right);
  }
}

public class Solution {
  private int count = 0;
  private int result = -1;
  public int kthSmallest(TreeNode root, int k) {
    inorderTraversal(root, k);
    return result;
  }
  private void inorderTraversal(TreeNode node, int k) {
    if (node == null || result != -1) return;
    inorderTraversal(node.left, k);
    count++;
    if (count == k) {
      result = node.val;
      return;
    }
    inorderTraversal(node.right, k);
  }
}

public class KthLargestElementInStream {
  private PriorityQueue<Integer> minHeap;
  private int k;

  public KthLargestElementInStream(int k) {
    this.k = k;
    this.minHeap = new PriorityQueue<>();
  }

  public void add(int num) {
    if (minHeap.size() < k) {
      minHeap.offer(num);
    } else if (num > minHeap.peek()) {
      minHeap.poll();
      minHeap.offer(num);
    }
  }

  public int getKthLargest() {
    return minHeap.peek();
  }
}

public class KthLargestElementInArray {
  public int findKthLargest(int[] nums, int k) {
    PriorityQueue<Integer> minHeap = new PriorityQueue<>();
    for (int num : nums) {
      if (minHeap.size() < k) {
        minHeap.offer(num);
      } else if (num > minHeap.peek()) {
        minHeap.poll();
        minHeap.offer(num);
      }
    }
    return minHeap.peek();
  }
}

public class SubsetsII {
  public List<List<Integer>> subsetsWithDup(int[] nums) {
    List<List<Integer>> result = new ArrayList<>();
    Arrays.sort(nums);
    backtrack(result, new ArrayList<>(), nums, 0);
    return result;
  }

  private void backtrack(List<List<Integer>> result, List<Integer> tempList, int[] nums, int start) {
    result.add(new ArrayList<>(tempList));
    for (int i = start; i < nums.length; i++) {
      if (i > start && nums[i] == nums[i - 1]) continue;
      tempList.add(nums[i]);
      backtrack(result, tempList, nums, i + 1);
      tempList.remove(tempList.size() - 1);
    }
  }
}

public class MaximumProductSubarray {
  public int maxProduct(int[] nums) {
    int maxSoFar = nums[0];
    int minSoFar = nums[0];
    int result = nums[0];
    for (int i = 1; i < nums.length; i++) {
      int temp = maxSoFar;
      maxSoFar = Math.max(Math.max(nums[i], maxSoFar * nums[i]), minSoFar * nums[i]);
      minSoFar = Math.min(Math.min(nums[i], temp * nums[i]), minSoFar * nums[i]);
      result = Math.max(result, maxSoFar);
    }
    return result;
  }
}

public class RotateImage {
  public int[][] rotate(int[][] matrix) {
    int n = matrix.length;
    for (int i = 0; i < n; i++) {
      for (int j = i; j < n; j++) {
        int temp = matrix[i][j];
        matrix[i][j] = matrix[j][i];
        matrix[j][i] = temp;
      }
    }
    for (int i = 0; i < n; i++) {
      for (int j = 0; j < n / 2; j++) {
        int temp = matrix[i][j];
        matrix[i][j] = matrix[i][n - j - 1];
        matrix[i][n - j - 1] = temp;
      }
    }
    return matrix;
  }
}

public List<List<Integer>> generate(int numRows) {
  // Initialize the result list
  List<List<Integer>> result = new ArrayList<>();

  // Handle edge case where numRows is 0
  if (numRows == 0) {
    return result;
  }

  // Initialize the first row
  List<Integer> firstRow = new ArrayList<>();
  firstRow.add(1);
  result.add(firstRow);

  // Generate subsequent rows
  for (int i = 1; i < numRows; i++) {
    List<Integer> currentRow = new ArrayList<>();
    List<Integer> previousRow = result.get(i - 1);

    // Calculate the sum of adjacent numbers
    for (int j = 0; j <= previousRow.size(); j++) {
      if (j == 0) {
        currentRow.add(1);
      } else if (j == previousRow.size()) {
        currentRow.add(1);
      } else {
        currentRow.add(previousRow.get(j - 1) + previousRow.get(j));
      }
    }

    // Add the current row to the result list
    result.add(currentRow);
  }

  return result;
}

public void sortColors(int[] nums) {
  // Initialize pointers
  int red = 0;
  int white = 0;
  int blue = nums.length - 1;

  // Partition the array
  while (white <= blue) {
    if (nums[white] == 0) {
      // Swap red and white
      int temp = nums[red];
      nums[red] = nums[white];
      nums[white] = temp;
      red++;
      white++;
    } else if (nums[white] == 1) {
      white++;
    } else {
      // Swap white and blue
      int temp = nums[white];
      nums[white] = nums[blue];
      nums[blue] = temp;
      blue--;
    }
  }
}

public int removeDuplicates(int[] nums) {
  // Initialize pointers
  int write = 1;

  // Iterate over the array
  for (int read = 1; read < nums.length; read++) {
    if (nums[read] != nums[read - 1]) {
      // Move the writing pointer forward
      nums[write] = nums[read];
      write++;
    }
  }

  return write;
}

public class MyStack {
  private Queue<Integer> queue;
  private Queue<Integer> temp;

  public MyStack() {
    queue = new LinkedList<>();
    temp = new LinkedList<>();
  }

  public void push(int x) {
    // Add the element to the temporary queue
    temp.offer(x);

    // Move all elements from the main queue to the temporary queue
    while (!queue.isEmpty()) {
      temp.offer(queue.poll());
    }

    // Swap the queues
    Queue<Integer> swap = queue;
    queue = temp;
    temp = swap;
  }

  public int pop() {
    // Remove the front element from the main queue
    return queue.poll();
  }
}

public ListNode middleNode(ListNode head) {
  // Initialize pointers
  ListNode slow = head;
  ListNode fast = head;

  // Traverse the linked list
  while (fast != null && fast.next != null) {
    slow = slow.next;
    fast = fast.next.next;
  }

  return slow;
}

public ListNode removeNthFromEnd(ListNode head, int n) {
  // Initialize two pointers
  ListNode p1 = head;
  ListNode p2 = head;

  // Move p1 nth nodes ahead
  for (int i = 0; i < n; i++) {
    p1 = p1.next;
  }

  // If p1 is null, remove the head node
  if (p1 == null) {
    return head.next;
  }

  // Move both pointers until p1 reaches the end
  while (p1.next != null) {
    p1 = p1.next;
    p2 = p2.next;
  }

  // Remove the next node of p2
  p2.next = p2.next.next;

  return head;
}

public Node copyRandomList(Node head) {
  // Create hash map to store copied nodes
  HashMap<Node, Node> map = new HashMap<>();

  // Copy nodes and store in hash map
  Node curr = head;
  while (curr != null) {
    map.put(curr, new Node(curr.val));
    curr = curr.next;
  }

  // Update random pointers
  curr = head;
  while (curr != null) {
    if (curr.random != null) {
      map.get(curr).random = map.get(curr.random);
    }
    curr = curr.next;
  }

  // Update next pointers
  curr = head;
  while (curr != null) {
    map.get(curr).next = map.get(curr.next);
    curr = curr.next;
  }

  return map.get(head);
}

public ListNode reverseKGroup(ListNode head, int k) {
  // Check if k nodes exist
  if (head == null || k == 1) {
    return head;
  }

  // Reverse k nodes
  ListNode curr = head;
  for (int i = 0; i < k; i++) {
    if (curr == null) {
      return head;
    }
    curr = curr.next;
  }

  // Reverse k nodes
  ListNode prev = null;
  curr = head;
  for (int i = 0; i < k; i++) {
    ListNode next = curr.next;
    curr.next = prev;
    prev = curr;
    curr = next;
  }

  // Connect reversed groups
  head.next = reverseKGroup(curr, k);

  return prev;
}

public List<Integer> rightSideView(TreeNode root) {
  // Initialize queue
  Queue<TreeNode> queue = new LinkedList<>();
  queue.add(root);

  // Initialize result list
  List<Integer> result = new ArrayList<>();

  // Perform level-order traversal
  while (!queue.isEmpty()) {
    int size = queue.size();
    for (int i = 0; i < size; i++) {
      TreeNode node = queue.poll();
      if (i == size - 1) {
        result.add(node.val);
      }
      if (node.left != null) {
        queue.add(node.left);
      }
      if (node.right != null) {
        queue.add(node.right);
      }
    }
  }

  return result;
}

public int maxPathSum(TreeNode root) {
  // Initialize maximum path sum
  int[] maxSum = new int[] {Integer.MIN_VALUE};

  // Define recursive function
  maxGain(root, maxSum);

  return maxSum[0];
}

public int maxGain(TreeNode node, int[] maxSum) {
  if (node == null) {
    return 0;
  }

  // Calculate maximum path sum for left and right subtrees
  int leftGain = Math.max(maxGain(node.left, maxSum), 0);
  int rightGain = Math.max(maxGain(node.right, maxSum), 0);

  // Update maximum path sum
  int priceNewpath = node.val + leftGain + rightGain;
  maxSum[0] = Math.max(maxSum[0], priceNewpath);

  // Return maximum path sum for current node
  return node.val + Math.max(leftGain, rightGain);
}

public class Solution {
  public List<List<Integer>> combinationSum2(int[] candidates, int target) {
    // Sort the input array
    Arrays.sort(candidates);
    List<List<Integer>> result = new ArrayList<>();
    backtrack(result, new ArrayList<>(), candidates, target, 0);
    return result;
  }

  private void backtrack(List<List<Integer>> result, List<Integer> tempList, int[] nums, int remain, int start) {
    if (remain < 0) return;
    else if (remain == 0) result.add(new ArrayList<>(tempList));
    else {
      for (int i = start; i < nums.length; i++) {
        // Avoid duplicates
        if (i > start && nums[i] == nums[i-1]) continue;
        tempList.add(nums[i]);
        backtrack(result, tempList, nums, remain - nums[i], i + 1);
        tempList.remove(tempList.size() - 1);
      }
    }
  }
}

public class Solution {
  public List<List<String>> solveNQueens(int n) {
    char[][] board = new char[n][n];
    for (int i = 0; i < n; i++) {
      for (int j = 0; j < n; j++) {
        board[i][j] = '.';
      }
    }
    List<List<String>> result = new ArrayList<>();
    backtrack(result, board, 0);
    return result;
  }

  private void backtrack(List<List<String>> result, char[][] board, int row) {
    if (row == board.length) {
      List<String> config = new ArrayList<>();
      for (char[] chars : board) {
        config.add(new String(chars));
      }
      result.add(config);
    } else {
      for (int col = 0; col < board.length; col++) {
        if (isValid(board, row, col)) {
          board[row][col] = 'Q';
          backtrack(result, board, row + 1);
          board[row][col] = '.';
        }
      }
    }
  }

  private boolean isValid(char[][] board, int row, int col) {
    for (int i = 0; i < row; i++) {
      for (int j = 0; j < board.length; j++) {
        if (board[i][j] == 'Q' && (j == col || Math.abs(j - col) == row - i)) {
          return false;
        }
      }
    }
    return true;
  }
}

public class Solution {
  public String longestPalindrome(String s) {
    int n = s.length();
    boolean[][] table = new boolean[n][n];
    int maxLen = 1;
    int start = 0;
    for (int i = n - 1; i >= 0; i--) {
      table[i][i] = true;
      for (int j = i + 1; j < n; j++) {
        if (s.charAt(i) == s.charAt(j)) {
          if (j - i == 1 || table[i + 1][j - 1]) {
            table[i][j] = true;
            if (j - i + 1 > maxLen) {
              maxLen = j - i + 1;
              start = i;
            }
          }
        }
      }
    }
    return s.substring(start, start + maxLen);
  }
}

