public class Solution {
  public double myPow(double x, int n) {
    if (n < 0) {
      return 1 / myPow(x, -n);
    }
    if (n == 0) {
      return 1;
    }
    if (n == 1) {
      return x;
    }
    double halfPow = myPow(x, n / 2);
    if (n % 2 == 0) {
      return halfPow * halfPow;
    } else {
      return halfPow * halfPow * x;
    }
  }
}

public int[] nextGreaterElement(int[] nums1, int[] nums2) {
  // Initialize stack and hash map
  Stack<Integer> stack = new Stack<>();
  Map<Integer, Integer> map = new HashMap<>();

  // Iterate through second array
  for (int num : nums2) {
    // Pop indices from stack that have a value less than the current element
    while (!stack.isEmpty() && stack.peek() < num) {
      map.put(stack.pop(), num);
    }
    // Push index to stack
    stack.push(num);
  }

  // Return next greater element array
  int[] result = new int[nums1.length];
  for (int i = 0; i < nums1.length; i++) {
    result[i] = map.getOrDefault(nums1[i], -1);
  }
  return result;
}

public void merge(int[] nums1, int m, int[] nums2, int n) {
  // Initialize pointers and temporary array
  int p1 = m - 1;
  int p2 = n - 1;
  int[] temp = new int[m + n];

  // Compare and merge elements
  for (int i = m + n - 1; i >= 0; i--) {
    if (p1 >= 0 && p2 >= 0) {
      if (nums1[p1] > nums2[p2]) {
        temp[i] = nums1[p1--];
      } else {
        temp[i] = nums2[p2--];
      }
    } else if (p1 >= 0) {
      temp[i] = nums1[p1--];
    } else {
      temp[i] = nums2[p2--];
    }
  }

  // Copy merged result to original array
  System.arraycopy(temp, 0, nums1, 0, m + n);
}

public TreeNode buildTree(int[] preorder, int[] inorder) {
  // Initialize indices
  int preIndex = 0;
  int inIndex = 0;

  // Identify root node
  TreeNode root = new TreeNode(preorder[preIndex++]);

  // Find root node in inorder sequence
  while (inIndex < inorder.length && inorder[inIndex] != root.val) {
    inIndex++;
  }

  // Construct left subtree
  if (inIndex > 0) {
    root.left = buildTree(Arrays.copyOfRange(preorder, 1, inIndex + 1), Arrays.copyOfRange(inorder, 0, inIndex));
  }

  // Construct right subtree
  if (inIndex < inorder.length - 1) {
    root.right = buildTree(Arrays.copyOfRange(preorder, inIndex + 1, preorder.length), Arrays.copyOfRange(inorder, inIndex + 1, inorder.length));
  }

  // Return constructed tree
  return root;
}

public int orangesRotting(int[][] grid) {
  // Initialize queue and variables
  Queue<int[]> queue = new LinkedList<>();
  int minutes = 0;
  int freshOranges = 0;

  // Add rotting oranges to queue
  for (int i = 0; i < grid.length; i++) {
    for (int j = 0; j < grid[0].length; j++) {
      if (grid[i][j] == 2) {
        queue.offer(new int[] {i, j});
      } else if (grid[i][j] == 1) {
        freshOranges++;
      }
    }
  }

  // Process cells in queue
  while (!queue.isEmpty()) {
    int size = queue.size();
    for (int i = 0; i < size; i++) {
      int[] cell = queue.poll();
      int x = cell[0];
      int y = cell[1];

      // Check all neighboring cells
      for (int[] dir : new int[][] {{-1, 0}, {1, 0}, {0, -1}, {0, 1}}) {
        int nx = x + dir[0];
        int ny = y + dir[1];

        // Rot any fresh oranges
        if (nx >= 0 && nx < grid.length && ny >= 0 && ny < grid[0].length && grid[nx][ny] == 1) {
          grid[nx][ny] = 2;
          queue.offer(new int[] {nx, ny});
          freshOranges--;
        }
      }
    }

    // Update variables
    minutes++;
  }

  // Return number of minutes
  return freshOranges == 0 ? minutes : -1;
}

public int romanToInt(String s) {
  // Initialize hash map and result
  Map<Character, Integer> map = new HashMap<>();
  map.put('I', 1);
  map.put('V', 5);
  map.put('X', 10);
  map.put('L', 50);
  map.put('C', 100);
  map.put('D', 500);
  map.put('M', 1000);
  int result = 0;

  // Iterate through string
  for (int i = 0; i < s.length(); i++) {
    // Update result
    if (i < s.length() - 1 && map.get(s.charAt(i)) < map.get(s.charAt(i + 1))) {
      result -= map.get(s.charAt(i));
    } else {
      result += map.get(s.charAt(i));
    }
  }

  // Return result
  return result;
}

public List<List<Integer>> fourSum(int[] nums, int target) {
  // Sort the array
  Arrays.sort(nums);
  List<List<Integer>> result = new ArrayList<>();
  for (int i = 0; i < nums.length - 3; i++) {
    // Skip duplicates for i
    if (i > 0 && nums[i] == nums[i - 1]) continue;
    for (int j = i + 1; j < nums.length - 2; j++) {
      // Skip duplicates for j
      if (j > i + 1 && nums[j] == nums[j - 1]) continue;
      int left = j + 1;
      int right = nums.length - 1;
      while (left < right) {
        int sum = nums[i] + nums[j] + nums[left] + nums[right];
        if (sum == target) {
          result.add(Arrays.asList(nums[i], nums[j], nums[left], nums[right]));
          // Skip duplicates for left and right
          while (left < right && nums[left] == nums[left + 1]) left++;
          while (left < right && nums[right] == nums[right - 1]) right--;
          left++;
          right--;
        } else if (sum < target) {
          left++;
        } else {
          right--;
        }
      }
    }
  }
  return result;
}

public List<Integer> preorderTraversal(TreeNode root) {
  List<Integer> result = new ArrayList<>();
  traverse(root, result);
  return result;
}

private void traverse(TreeNode node, List<Integer> result) {
  if (node == null) return;
  // Visit the root
  result.add(node.val);
  // Traverse the left subtree
  traverse(node.left, result);
  // Traverse the right subtree
  traverse(node.right, result);
}

public List<Integer> postorderTraversal(TreeNode root) {
  List<Integer> result = new ArrayList<>();
  traverse(root, result);
  return result;
}

private void traverse(TreeNode node, List<Integer> result) {
  if (node == null) return;
  // Traverse the left subtree
  traverse(node.left, result);
  // Traverse the right subtree
  traverse(node.right, result);
  // Visit the root
  result.add(node.val);
}

