public int singleNonDuplicate(int[] nums) {
  int left = 0;
  int right = nums.length - 1;
  while (left < right) {
    int mid = left + (right - left) / 2;
    if (mid % 2 == 1) {
      mid--;
    }
    if (nums[mid] == nums[mid + 1]) {
      left = mid + 2;
    } else {
      right = mid;
    }
  }
  return nums[left];
}

public class Solution {
  public boolean isPalindrome(ListNode head) {
    // Find the end of first half and reverse second half.
    ListNode firstHalfEnd = endOfFirstHalf(head);
    ListNode secondHalfStart = reverseList(firstHalfEnd.next);

    // Check whether or not there's a palindrome.
    ListNode p1 = head;
    ListNode p2 = secondHalfStart;
    boolean result = true;
    while (result && p2 != null) {
      if (p1.val != p2.val) result = false;
      p1 = p1.next;
      p2 = p2.next;
    } 

    // Restore the list and return the result.
    firstHalfEnd.next = reverseList(secondHalfStart);
    return result;
  }

  private ListNode endOfFirstHalf(ListNode head) {
    ListNode slow = head;
    ListNode fast = head;
    while (fast.next != null && fast.next.next != null) {
      slow = slow.next;
      fast = fast.next.next;
    }
    return slow;
  }

  private ListNode reverseList(ListNode head) {
    ListNode prev = null;
    ListNode curr = head;
    while (curr != null) {
      ListNode nextTemp = curr.next;
      curr.next = prev;
      prev = curr;
      curr = nextTemp;
    }
    return prev;
  }
}

public class Solution {
  public ListNode getIntersectionNode(ListNode headA, ListNode headB) {
    int lenA = length(headA);
    int lenB = length(headB);
    if (lenA > lenB) {
      headA = moveForward(headA, lenA - lenB);
    } else {
      headB = moveForward(headB, lenB - lenA);
    }
    while (headA != null && headB != null) {
      if (headA == headB) {
        return headA;
      }
      headA = headA.next;
      headB = headB.next;
    }
    return null;
  }

  private int length(ListNode head) {
    int len = 0;
    while (head != null) {
      len++;
      head = head.next;
    }
    return len;
  }

  private ListNode moveForward(ListNode head, int steps) {
    while (steps > 0) {
      head = head.next;
      steps--;
    }
    return head;
  }
}

public class Solution {
  public TreeNode sortedArrayToBST(int[] nums) {
    return sortedArrayToBST(nums, 0, nums.length - 1);
  }

  private TreeNode sortedArrayToBST(int[] nums, int left, int right) {
    if (left > right) {
      return null;
    }
    int mid = left + (right - left) / 2;
    TreeNode root = new TreeNode(nums[mid]);
    root.left = sortedArrayToBST(nums, left, mid - 1);
    root.right = sortedArrayToBST(nums, mid + 1, right);
    return root;
  }
}

public class Solution {
  public boolean isSymmetric(TreeNode root) {
    return isMirror(root, root);
  }

  private boolean isMirror(TreeNode t1, TreeNode t2) {
    if (t1 == null && t2 == null) {
      return true;
    }
    if (t1 == null || t2 == null) {
      return false;
    }
    return (t1.val == t2.val) && isMirror(t1.right, t2.left) && isMirror(t1.left, t2.right);
  }
}

public class Solution {
  public Node connect(Node root) {
    if (root == null) {
      return null;
    }
    Queue<Node> queue = new LinkedList<>();
    queue.offer(root);
    while (!queue.isEmpty()) {
      int size = queue.size();
      for (int i = 0; i < size; i++) {
        Node node = queue.poll();
        if (i < size - 1) {
          node.next = queue.peek();
        }
        if (node.left != null) {
          queue.offer(node.left);
        }
        if (node.right != null) {
          queue.offer(node.right);
        }
      }
    }
    return root;
  }
}

public List<List<Integer>> zigzagLevelOrder(TreeNode root) {
  // Initialize queue and flag
  Queue<TreeNode> queue = new LinkedList<>();
  queue.add(root);
  boolean reverse = false;
  List<List<Integer>> result = new ArrayList<>();

  // Perform level order traversal
  while (!queue.isEmpty()) {
    List<Integer> level = new ArrayList<>();
    int size = queue.size();
    for (int i = 0; i < size; i++) {
      TreeNode node = queue.poll();
      if (reverse) {
        level.add(0, node.val);
      } else {
        level.add(node.val);
      }
      if (node.left != null) {
        queue.add(node.left);
      }
      if (node.right != null) {
        queue.add(node.right);
      }
    }
    result.add(level);
    reverse = !reverse;
  }
  return result;
}

public ListNode rotateRight(ListNode head, int k) {
  // Calculate list length
  if (head == null || head.next == null) {
    return head;
  }
  ListNode oldTail = head;
  int n = 1;
  while (oldTail.next != null) {
    oldTail = oldTail.next;
    n++;
  }

  // Find new tail and head
  k = k % n;
  if (k == 0) {
    return head;
  }
  ListNode newTail = head;
  for (int i = 0; i < n - k - 1; i++) {
    newTail = newTail.next;
  }
  ListNode newHead = newTail.next;

  // Connect new tail to None
  newTail.next = null;

  // Connect old tail to new head
  oldTail.next = head;

  // Return new head
  return newHead;
}

public TreeNode buildTree(int[] inorder, int[] postorder) {
  // Identify root from postorder traversal
  if (inorder.length == 0) {
    return null;
  }
  TreeNode root = new TreeNode(postorder[postorder.length - 1]);

  // Find left and right subtrees from inorder traversal
  int index = 0;
  while (inorder[index] != postorder[postorder.length - 1]) {
    index++;
  }
  int[] leftInorder = Arrays.copyOfRange(inorder, 0, index);
  int[] rightInorder = Arrays.copyOfRange(inorder, index + 1, inorder.length);
  int[] leftPostorder = Arrays.copyOfRange(postorder, 0, index);
  int[] rightPostorder = Arrays.copyOfRange(postorder, index, postorder.length - 1);

  // Recursively construct left and right subtrees
  root.left = buildTree(leftInorder, leftPostorder);
  root.right = buildTree(rightInorder, rightPostorder);

  // Return constructed tree
  return root;
}

public class BSTIterator {
  private Stack<TreeNode> stack;
  private TreeNode current;

  public BSTIterator(TreeNode root) {
    stack = new Stack<>();
    current = root;
  }

  public int next() {
    // Push left children onto stack
    while (current != null) {
      stack.push(current);
      current = current.left;
    }

    // Yield node value
    current = stack.pop();
    int result = current.val;

    // Push right child onto stack
    current = current.right;

    return result;
  }

  public boolean hasNext() {
    return current != null || !stack.isEmpty();
  }
}

public int minPathSum(int[][] grid) {
  // Initialize 2D array
  int[][] dp = new int[grid.length][grid[0].length];

  // Fill in first row and column
  dp[0][0] = grid[0][0];
  for (int i = 1; i < grid.length; i++) {
    dp[i][0] = dp[i - 1][0] + grid[i][0];
  }
  for (int j = 1; j < grid[0].length; j++) {
    dp[0][j] = dp[0][j - 1] + grid[0][j];
  }

  // Fill in rest of 2D array
  for (int i = 1; i < grid.length; i++) {
    for (int j = 1; j < grid[0].length; j++) {
      dp[i][j] = Math.min(dp[i - 1][j], dp[i][j - 1]) + grid[i][j];
    }
  }

  // Return minimum path sum
  return dp[grid.length - 1][grid[0].length - 1];
}

class LFUCache {
    class Node {
        int key, val, freq;
        Node prev, next;
        Node(int key, int val) { this.key = key; this.val = val; this.freq = 1; }
    }
    class DLinkedList {
        Node head, tail;
        void add(Node node) { /* add node to head */ }
        void remove(Node node) { /* remove node */ }
        Node removeLast() { /* remove and return tail */ }
        boolean isEmpty() { /* check if empty */ }
    }
    Map<Integer, Node> cache;
    Map<Integer, DLinkedList> freqMap;
    int capacity, minFreq;

    public LFUCache(int capacity) {
        this.capacity = capacity;
        this.cache = new HashMap<>();
        this.freqMap = new HashMap<>();
        this.minFreq = 0;
    }

    public int get(int key) {
        if (!cache.containsKey(key)) return -1;
        Node node = cache.get(key);
        updateFreq(node);
        return node.val;
    }

    public void put(int key, int value) {
        if (capacity <= 0) return;
        if (cache.containsKey(key)) {
            Node node = cache.get(key);
            node.val = value;
            updateFreq(node);
        } else {
            if (cache.size() >= capacity) {
                DLinkedList minList = freqMap.get(minFreq);
                Node removed = minList.removeLast();
                cache.remove(removed.key);
            }
            Node newNode = new Node(key, value);
            cache.put(key, newNode);
            DLinkedList newList = freqMap.getOrDefault(1, new DLinkedList());
            newList.add(newNode);
            freqMap.put(1, newList);
            minFreq = 1;
        }
    }

    private void updateFreq(Node node) {
        int freq = node.freq;
        DLinkedList list = freqMap.get(freq);
        list.remove(node);
        if (list.isEmpty() && freq == minFreq) {
            minFreq++;
        }
        node.freq++;
        DLinkedList newList = freqMap.getOrDefault(node.freq, new DLinkedList());
        newList.add(node);
        freqMap.put(node.freq, newList);
    }
}

class Solution {
    class Pair {
        TreeNode node;
        long index;
        Pair(TreeNode node, long index) { this.node = node; this.index = index; }
    }

    public int widthOfBinaryTree(TreeNode root) {
        if (root == null) return 0;
        Queue<Pair> queue = new LinkedList<>();
        queue.offer(new Pair(root, 0));
        int maxWidth = 0;

        while (!queue.isEmpty()) {
            int levelSize = queue.size();
            long minIndex = queue.peek().index;
            long maxIndex = minIndex;

            for (int i = 0; i < levelSize; i++) {
                Pair current = queue.poll();
                TreeNode currentNode = current.node;
                long currentIndex = current.index;

                maxIndex = currentIndex; // Update max index for the current level

                if (currentNode.left != null) {
                    queue.offer(new Pair(currentNode.left, 2 * currentIndex));
                }
                if (currentNode.right != null) {
                    queue.offer(new Pair(currentNode.right, 2 * currentIndex + 1));
                }
            }
            maxWidth = Math.max(maxWidth, (int)(maxIndex - minIndex + 1));
        }
        return maxWidth;
    }
}

class Solution {
    public boolean isBipartite(int[][] graph) {
        int n = graph.length;
        int[] colors = new int[n]; // 0: uncolored, 1: color A, 2: color B
        Arrays.fill(colors, 0);

        for (int i = 0; i < n; i++) {
            if (colors[i] == 0) { // If node i is uncolored
                if (!bfs(graph, colors, i)) {
                    return false;
                }
            }
        }
        return true;
    }

    private boolean bfs(int[][] graph, int[] colors, int startNode) {
        Queue<Integer> queue = new LinkedList<>();
        queue.offer(startNode);
        colors[startNode] = 1; // Start with color 1

        while (!queue.isEmpty()) {
            int u = queue.poll();
            int currentColor = colors[u];
            int neighborColor = (currentColor == 1) ? 2 : 1;

            for (int v : graph[u]) {
                if (colors[v] == 0) { // Neighbor is uncolored
                    colors[v] = neighborColor;
                    queue.offer(v);
                } else if (colors[v] == currentColor) { // Neighbor has the same color
                    return false;
                }
            }
        }
        return true;
    }
}

