class Solution {
    public int lengthOfLastWord(String s) {
        int length = 0;
        int n = s.length();

        // Trim trailing spaces by moving pointer from the end
        int i = n - 1;
        while (i >= 0 && s.charAt(i) == ' ') {
            i--;
        }

        // Count the length of the last word
        while (i >= 0 && s.charAt(i) != ' ') {
            length++;
            i--;
        }

        return length;
    }
}

class Solution {
    public int minCostClimbingStairs(int[] cost) {
        int n = cost.length;
        if (n == 0) return 0;
        if (n == 1) return cost[0];

        // dp[i] = min cost to reach step i
        int[] dp = new int[n];
        dp[0] = cost[0];
        dp[1] = cost[1];

        for (int i = 2; i < n; i++) {
            dp[i] = cost[i] + Math.min(dp[i - 1], dp[i - 2]);
        }

        // The top can be reached from step n-1 or n-2
        return Math.min(dp[n - 1], dp[n - 2]);
    }
}

class Solution {
    public int[] replaceElements(int[] arr) {
        int n = arr.length;
        int max_so_far = -1;

        // Iterate from right to left
        for (int i = n - 1; i >= 0; i--) {
            int temp = arr[i]; // Store current element
            arr[i] = max_so_far; // Replace with max from right
            max_so_far = Math.max(max_so_far, temp); // Update max_so_far
        }

        return arr;
    }
}

class Solution {
    public boolean isSubsequence(String s, String t) {
        int s_ptr = 0;
        int t_ptr = 0;

        // Iterate while both pointers are within their respective string bounds
        while (s_ptr < s.length() && t_ptr < t.length()) {
            // If characters match, advance the pointer for s
            if (s.charAt(s_ptr) == t.charAt(t_ptr)) {
                s_ptr++;
            }
            // Always advance the pointer for t
            t_ptr++;
        }

        // If s_ptr reached the end of s, it's a subsequence
        return s_ptr == s.length();
    }
}

class Solution {
    public boolean isValidSudoku(char[][] board) {
        HashSet<Character>[] rows = new HashSet[9];
        HashSet<Character>[] cols = new HashSet[9];
        HashSet<Character>[] boxes = new HashSet[9];

        for (int i = 0; i < 9; i++) {
            rows[i] = new HashSet<>();
            cols[i] = new HashSet<>();
            boxes[i] = new HashSet<>();
        }

        for (int r = 0; r < 9; r++) {
            for (int c = 0; c < 9; c++) {
                char num = board[r][c];
                if (num == '.') {
                    continue;
                }

                int boxIndex = (r / 3) * 3 + c / 3;

                if (rows[r].contains(num) || cols[c].contains(num) || boxes[boxIndex].contains(num)) {
                    return false;
                }

                rows[r].add(num);
                cols[c].add(num);
                boxes[boxIndex].add(num);
            }
        }

        return true;
    }
}

import java.util.Arrays; 
import java.util.Comparator;

class Solution {
    public String largestNumber(int[] nums) {
        if (nums == null || nums.length == 0) {
            return "";
        }

        String[] sNums = new String[nums.length];
        for (int i = 0; i < nums.length; i++) {
            sNums[i] = String.valueOf(nums[i]);
        }

        Comparator<String> comp = (str1, str2) -> {
            String order1 = str1 + str2;
            String order2 = str2 + str1;
            return order2.compareTo(order1); // Descending order
        };

        Arrays.sort(sNums, comp);

        if (sNums[0].equals("0")) {
            return "0";
        }

        StringBuilder sb = new StringBuilder();
        for (String s : sNums) {
            sb.append(s);
        }

        return sb.toString();
    }
}

class Solution {
    public int[] twoSum(int[] numbers, int target) {
        int l = 0;
        int r = numbers.length - 1;

        while (l < r) {
            int sum = numbers[l] + numbers[r];
            if (sum == target) {
                return new int[]{l + 1, r + 1};
            } else if (sum < target) {
                l++;
            } else { // sum > target
                r--;
            }
        }
        // Should not reach here based on problem constraints
        return new int[]{-1, -1};
    }
}

import java.util.Stack;

class Solution {
    public int evalRPN(String[] tokens) {
        Stack<Integer> stack = new Stack<>();

        for (String token : tokens) {
            if (isOperator(token)) {
                int operand2 = stack.pop();
                int operand1 = stack.pop();
                int result = performOperation(operand1, operand2, token);
                stack.push(result);
            } else {
                stack.push(Integer.parseInt(token));
            }
        }

        return stack.pop();
    }

    private boolean isOperator(String token) {
        return token.equals("+") || token.equals("-") || token.equals("*") || token.equals("/");
    }

    private int performOperation(int a, int b, String op) {
        switch (op) {
            case "+": return a + b;
            case "-": return a - b;
            case "*": return a * b;
            case "/": return a / b; // Integer division, truncates towards zero
            default: throw new IllegalArgumentException("Unknown operator: " + op);
        }
    }
}

class Solution {
    public int findMin(int[] nums) {
        int l = 0;
        int r = nums.length - 1;

        while (l < r) {
            int mid = l + (r - l) / 2;

            if (nums[mid] < nums[r]) {
                // Minimum is in the left half (including mid)
                r = mid;
            } else if (nums[mid] > nums[r]) {
                // Minimum is in the right half (excluding mid)
                l = mid + 1;
            } else { 
                // Handle duplicates: if nums[mid] == nums[r], we can discard nums[r]
                r--; 
            }
        }
        // When l == r, we've found the minimum element
        return nums[l];
    }
}

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) { 
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
class Solution {
    public boolean isSubtree(TreeNode s, TreeNode t) {
        if (s == null) {
            return false; // t cannot be a subtree of a null tree unless t is also null (handled below)
        }
        if (t == null) {
            return true; // An empty tree is a subtree of any tree
        }
        if (isSameTree(s, t)) {
            return true;
        }
        // Check if t is a subtree of s's left or right child
        return isSubtree(s.left, t) || isSubtree(s.right, t);
    }

    private boolean isSameTree(TreeNode p, TreeNode q) {
        if (p == null && q == null) {
            return true;
        }
        if (p == null || q == null) {
            return false;
        }
        if (p.val != q.val) {
            return false;
        }
        // Recursively check left and right subtrees
        return isSameTree(p.left, q.left) && isSameTree(p.right, q.right);
    }
}

class TrieNode {
    TrieNode[] children = new TrieNode[26];
    boolean isEndOfWord = false;
}

class WordDictionary {
    private TrieNode root;

    public WordDictionary() {
        root = new TrieNode();
    }

    public void addWord(String word) {
        TrieNode node = root;
        for (char c : word.toCharArray()) {
            int index = c - 'a';
            if (node.children[index] == null) {
                node.children[index] = new TrieNode();
            }
            node = node.children[index];
        }
        node.isEndOfWord = true;
    }

    public boolean search(String word) {
        return searchHelper(root, word, 0);
    }

    private boolean searchHelper(TrieNode node, String word, int index) {
        if (node == null) {
            return false;
        }
        if (index == word.length()) {
            return node.isEndOfWord;
        }

        char c = word.charAt(index);

        if (c == '.') {
            // Wildcard: try all possible children
            for (int i = 0; i < 26; i++) {
                if (searchHelper(node.children[i], word, index + 1)) {
                    return true;
                }
            }
            return false;
        } else {
            // Specific character
            int charIndex = c - 'a';
            if (node.children[charIndex] == null) {
                return false;
            }
            return searchHelper(node.children[charIndex], word, index + 1);
        }
    }
}

class Solution {
    public int rob(int[] nums) {
        if (nums == null || nums.length == 0) {
            return 0;
        }
        int n = nums.length;
        if (n == 1) {
            return nums[0];
        }

        // DP approach with space optimization
        int prev2 = 0; // Represents dp[i-2]
        int prev1 = 0; // Represents dp[i-1]

        for (int i = 0; i < n; i++) {
            // current max = max(rob current house + money from i-2, don't rob current house = money from i-1)
            int currentMax = Math.max(nums[i] + prev2, prev1);
            prev2 = prev1;
            prev1 = currentMax;
        }

        return prev1; // prev1 holds the max amount for n houses
    }
}

class Solution {
    public int rob(int[] nums) {
        int n = nums.length;
        if (n == 0) return 0;
        if (n == 1) return nums[0];

        // Case 1: Rob houses 0 to n-2
        int max1 = robLinear(nums, 0, n - 2);
        // Case 2: Rob houses 1 to n-1
        int max2 = robLinear(nums, 1, n - 1);

        return Math.max(max1, max2);
    }

    private int robLinear(int[] nums, int start, int end) {
        if (start > end) return 0;
        if (start == end) return nums[start];

        int prev2 = 0; // dp[i-2]
        int prev1 = 0; // dp[i-1]

        for (int i = start; i <= end; i++) {
            int current = Math.max(prev1, prev2 + nums[i]);
            prev2 = prev1;
            prev1 = current;
        }
        return prev1;
    }
}

class Solution {
