class Solution {
    public int reverse(int x) {
        int reversedNum = 0;
        while (x != 0) {
            int digit = x % 10;
            x /= 10;

            // Check for overflow before multiplication
            if (reversedNum > Integer.MAX_VALUE / 10 || (reversedNum == Integer.MAX_VALUE / 10 && digit > 7)) return 0;
            if (reversedNum < Integer.MIN_VALUE / 10 || (reversedNum == Integer.MIN_VALUE / 10 && digit < -8)) return 0;

            reversedNum = reversedNum * 10 + digit;
        }
        return reversedNum;
    }
}

class Solution {
    public int removeElement(int[] nums, int val) {
        int writeIndex = 0; // Pointer for the position to place the next non-val element
        for (int readIndex = 0; readIndex < nums.length; readIndex++) {
            if (nums[readIndex] != val) {
                nums[writeIndex] = nums[readIndex]; // Overwrite or place the element
                writeIndex++; // Move the write pointer forward
            }
        }
        return writeIndex; // The new length of the array after removal
    }
}

import java.util.HashSet;
import java.util.Set;

class Solution {
    public int numUniqueEmails(String[] emails) {
        Set<String> uniqueEmails = new HashSet<>();

        for (String email : emails) {
            String[] parts = email.split("@");
            String localName = parts[0];
            String domainName = parts[1];

            // Normalize local name: remove dots
            localName = localName.replace(".", "");

            // Normalize local name: handle plus sign
            int plusIndex = localName.indexOf('+');
            if (plusIndex != -1) {
                localName = localName.substring(0, plusIndex);
            }

            // Reconstruct and add to set
            uniqueEmails.add(localName + "@" + domainName);
        }

        return uniqueEmails.size();
    }
}

class Solution {
    public int[] productExceptSelf(int[] nums) {
        int n = nums.length;
        int[] answer = new int[n];

        // Calculate prefix products and store in answer array
        answer[0] = 1;
        for (int i = 1; i < n; i++) {
            answer[i] = answer[i - 1] * nums[i - 1];
        }

        // Calculate suffix products and multiply with prefix products
        int suffixProduct = 1;
        for (int i = n - 1; i >= 0; i--) {
            answer[i] = answer[i] * suffixProduct;
            suffixProduct *= nums[i];
        }

        return answer;
    }
}

class Solution {
    public void reverseString(char[] s) {
        int left = 0;
        int right = s.length - 1;

        while (left < right) {
            // Swap characters
            char temp = s[left];
            s[left] = s[right];
            s[right] = temp;

            // Move pointers towards the center
            left++;
            right--;
        }
    }
}

import java.util.HashMap;
import java.util.Map;

class Solution {
    public int characterReplacement(String s, int k) {
        int left = 0;
        int maxLength = 0;
        int maxFrequency = 0;
        Map<Character, Integer> frequencyMap = new HashMap<>();

        for (int right = 0; right < s.length(); right++) {
            char currentChar = s.charAt(right);
            frequencyMap.put(currentChar, frequencyMap.getOrDefault(currentChar, 0) + 1);
            maxFrequency = Math.max(maxFrequency, frequencyMap.get(currentChar));

            // Calculate replacements needed
            int replacementsNeeded = (right - left + 1) - maxFrequency;

            // If replacements needed exceed k, shrink the window
            if (replacementsNeeded > k) {
                char leftChar = s.charAt(left);
                frequencyMap.put(leftChar, frequencyMap.get(leftChar) - 1);
                left++;
            }

            // Update max length (window size is always right - left + 1)
            maxLength = Math.max(maxLength, right - left + 1);
        }

        return maxLength;
    }
}

class Solution {
    List<String> result;
    int n;

    public List<String> generateParenthesis(int n) {
        this.result = new ArrayList<>();
        this.n = n;
        backtrack("", 0, 0);
        return result;
    }

    private void backtrack(String current, int openCount, int closeCount) {
        // Base case: if the string is complete
        if (current.length() == 2 * n) {
            result.add(current);
            return;
        }

        // Add opening parenthesis if possible
        if (openCount < n) {
            backtrack(current + "(", openCount + 1, closeCount);
        }

        // Add closing parenthesis if valid
        if (closeCount < openCount) {
            backtrack(current + ")", openCount, closeCount + 1);
        }
    }
}

class Solution {
    public int[] dailyTemperatures(int[] temperatures) {
        int n = temperatures.length;
        int[] answer = new int[n];
        Stack<Integer> stack = new Stack<>(); // Stores indices

        for (int i = 0; i < n; i++) {
            // While stack is not empty and current temp is warmer than temp at stack top index
            while (!stack.isEmpty() && temperatures[i] > temperatures[stack.peek()]) {
                int prevIndex = stack.pop();
                answer[prevIndex] = i - prevIndex;
            }
            // Push current index onto the stack
            stack.push(i);
        }

        // Days for which no warmer day is found will remain 0 in the answer array
        return answer;
    }
}

class Solution {
    public int carFleet(int target, int[] position, int[] speed) {
        int n = position.length;
        if (n == 0) return 0;

        // Combine position and speed, and sort by position
        double[][] cars = new double[n][2];
        for (int i = 0; i < n; i++) {
            cars[i][0] = position[i];
            cars[i][1] = (double)(target - position[i]) / speed[i]; // Arrival time
        }
        Arrays.sort(cars, (a, b) -> Double.compare(a[0], b[0]));

        Stack<Double> stack = new Stack<>(); // Stores arrival times of fleet leaders
        int fleetCount = 0;

        // Iterate from right to left (closest to target first)
        for (int i = n - 1; i >= 0; i--) {
            double arrivalTime = cars[i][1];
            if (stack.isEmpty() || arrivalTime > stack.peek()) {
                stack.push(arrivalTime);
                fleetCount++;
            }
        }

        return fleetCount;
    }
}

class Solution {
    public int searchInsert(int[] nums, int target) {
        int low = 0;
        int high = nums.length - 1;

        while (low <= high) {
            int mid = low + (high - low) / 2; // Avoid overflow

            if (nums[mid] == target) {
                return mid; // Target found
            } else if (nums[mid] < target) {
                low = mid + 1; // Search in the right half
            } else {
                high = mid - 1; // Search in the left half
            }
        }

        // If target is not found, low is the insertion point
        return low;
    }
}

import java.util.*;

class TimeMap {
    private Map<String, List<Pair<Integer, String>>> map;

    public TimeMap() {
        map = new HashMap<>();
    }

    public void set(String key, String value, int timestamp) {
        map.computeIfAbsent(key, k -> new ArrayList<>()).add(new Pair<>(timestamp, value));
    }

    public String get(String key, int timestamp) {
        List<Pair<Integer, String>> list = map.get(key);
        if (list == null) {
            return "";
        }

        int low = 0;
        int high = list.size() - 1;
        String result = "";

        while (low <= high) {
            int mid = low + (high - low) / 2;
            Pair<Integer, String> current = list.get(mid);

            if (current.getKey() <= timestamp) {
                result = current.getValue(); // Found a potential match, try for a later timestamp
                low = mid + 1;
            } else {
                high = mid - 1; // Timestamp is too large, search earlier
            }
        }
        return result;
    }

    // Helper Pair class (or use Map.Entry or a custom class)
    private static class Pair<K, V> {
        K key;
        V value;
        public Pair(K key, V value) { this.key = key; this.value = value; }
        public K getKey() { return key; }
        public V getValue() { return value; }
    }
}

import java.util.PriorityQueue;
import java.util.Collections;

class Solution {
    public int lastStoneWeight(int[] stones) {
        // Create a max heap (PriorityQueue)
        PriorityQueue<Integer> maxHeap = new PriorityQueue<>(Collections.reverseOrder());

        // Add all stones to the heap
        for (int stone : stones) {
            maxHeap.offer(stone);
        }

        // Process stones until only one or zero remain
        while (maxHeap.size() > 1) {
            int stone1 = maxHeap.poll(); // Heaviest stone
            int stone2 = maxHeap.poll(); // Second heaviest stone

            if (stone1 != stone2) {
                // Add the difference back to the heap
                maxHeap.offer(stone1 - stone2);
            }
        }

        // Return the last stone's weight or 0 if none remain
        return maxHeap.isEmpty() ? 0 : maxHeap.poll();
    }
}

class Solution {
    public int numDecodings(String s) {
        if (s == null || s.length() == 0) {
            return 0;
        }

        int n = s.length();
        int[] dp = new int[n + 1];
        dp[0] = 1; // Base case: one way to decode an empty string

        // Base case for the first character
        dp[1] = (s.charAt(0) == '0') ? 0 : 1;

        for (int i = 2; i <= n; i++) {
            // Check single digit decoding
            int oneDigit = Integer.parseInt(s.substring(i - 1, i));
            if (oneDigit >= 1 && oneDigit <= 9) {
                dp[i] += dp[i - 1];
            }

            // Check two digit decoding
            int twoDigits = Integer.parseInt(s.substring(i - 2, i));
            if (twoDigits >= 10 && twoDigits <= 26) {
                dp[i] += dp[i - 2];
            }
        }

        return dp[n];
    }
}

class Solution {
    public int jump(int[] nums) {
        int n = nums.length;
        if (n <= 1) {
            return 0; // Already at the end or only one element
        }

        int jumps = 0;
        int currentReach = 0; // The farthest index reachable with the current number of jumps
        int maxReach = 0;     // The farthest index reachable overall so far

        for (int i = 0; i < n - 1; i++) {
            // Update the maximum reach possible from the current position
            maxReach = Math.max(maxReach, i + nums[i]);

            // If we have reached the end of the range for the current jump
            if (i == currentReach) {
                jumps++; // Make a new jump
                currentReach = maxReach; // Update the boundary for the next jump

                // Optimization: If the current reach is already at or beyond the end, we can stop
                if (currentReach >= n - 1) {
                    break;
                }
            }
        }

        return jumps;
    }
}

class Solution {
    public int eraseOverlapIntervals(int[][] intervals) {
        if (intervals == null || intervals.length == 0) {
            return 0;
        }
        // Sort intervals by end time
        Arrays.sort(intervals, (a, b) -> Integer.compare(a[1], b[1]));

        int count = 1; // Count of non-overlapping intervals
        int prevEnd = intervals[0][1]; // End time of the first interval

        for (int i = 1; i < intervals.length; i++) {
            // If current interval does not overlap with the previous one
            if (intervals[i][0] >= prevEnd) {
                count++;
                prevEnd = intervals[i][1];
            }
        }

        // The number of intervals to remove is total intervals - non-overlapping intervals
        return intervals.length - count;
    }
}

class Solution {
    public boolean isHappy(int n) {
        Set<Integer> seen = new HashSet<>();
        while (n != 1 && !seen.contains(n)) {
            seen.add(n);
            n = getNext(n);
        }
        return n == 1;
    }

    private int getNext(int n) {
        int sum = 0;
        while (n > 0) {
            int digit = n % 10;
            sum += digit * digit;
            n /= 10;
        }
        return sum;
    }
}

class Solution {
    public int[] plusOne(int[] digits) {
        int n = digits.length;
        // Iterate from the last digit to the first
        for (int i = n - 1; i >= 0; i--) {
            // Increment the current digit
            digits[i]++;
            // If the digit is less than 10, no carry, return the array
            if (digits[i] < 10) {
                return digits;
            }
            // If the digit is 10, set it to 0 and continue (carry)
            digits[i] = 0;
        }

        // If we reach here, it means all digits were 9 and became 0
        // We need to add a leading 1
        int[] newNumber = new int[n + 1];
        newNumber[0] = 1;
        // The rest of the digits are already 0 from the loop
        return newNumber;
    }
}

class Solution {
    public int missingNumber(int[] nums) {
        int n = nums.length;
        int missing = n; // Initialize with n because the range is 0 to n

        for (int i = 0; i < n; i++) {
            // XOR with the index and the corresponding element
            missing ^= i ^ nums[i]; 
        }

        // The remaining value in 'missing' is the missing number
        return missing;
    }
}

class Solution {
    public int getSum(int a, int b) {
        // Loop continues as long as there is a carry (b != 0)
        while (b != 0) {
            // Calculate carry: find common set bits and shift left
            int carry = (a & b) << 1;
            // Calculate sum without carry using XOR
            a = a ^ b;
            // Update b to be the carry for the next iteration
            b = carry;
        }
        // When carry (b) is 0, 'a' holds the final sum
        return a;
    }
}

class Solution {
    public boolean isIsomorphic(String s, String t) {
        if (s.length() != t.length()) {
            return false;
        }

        Map<Character, Character> mapS = new HashMap<>();
        Map<Character, Character> mapT = new HashMap<>();

        for (int i = 0; i < s.length(); i++) {
            char sChar = s.charAt(i);
            char tChar = t.charAt(i);

            // Check mapping from s to t
            if (mapS.containsKey(sChar)) {
                if (mapS.get(sChar) != tChar) {
                    return false;
                }
            } else {
                mapS.put(sChar, tChar);
            }

            // Check mapping from t to s (ensures one-to-one)
            if (mapT.containsKey(tChar)) {
                if (mapT.get(tChar) != sChar) {
                    return false;
                }
            } else {
                mapT.put(tChar, sChar);
            }
        }

        return true;
    }
}

class Solution {
    public boolean canPlaceFlowers(int[] flowerbed, int n) {
        int length = flowerbed.length;

        for (int i = 0; i < length; i++) {
            // Check if the current plot is empty
            if (flowerbed[i] == 0) {
                // Check left neighbor (or boundary)
                boolean leftEmpty = (i == 0) || (flowerbed[i - 1] == 0);
                // Check right neighbor (or boundary)
                boolean rightEmpty = (i == length - 1) || (flowerbed[i + 1] == 0);

                // If both neighbors are empty, plant a flower
                if (leftEmpty && rightEmpty) {
                    flowerbed[i] = 1; // Plant the flower
                    n--; // Decrement the count of flowers needed

                    // If we have planted enough flowers, return true
                    if (n == 0) {
                        return true;
                    }
                }
            }
        }

        // Return true if all n flowers were planted, false otherwise
        return n == 0;
    }
}

class Solution {
    public int pivotIndex(int[] nums) {
        int totalSum = 0;
        // Calculate the total sum of the array
        for (int num : nums) {
            totalSum += num;
        }

        int leftSum = 0;
        // Iterate through the array to find the pivot index
        for (int i = 0; i < nums.length; i++) {
            // Calculate the right sum
            // rightSum = totalSum - leftSum - current element
            int rightSum = totalSum - leftSum - nums[i];

            // Check if leftSum equals rightSum
            if (leftSum == rightSum) {
                return i; // Found the pivot index
            }

            // Update leftSum for the next iteration
            leftSum += nums[i];
        }

        // If no pivot index is found after checking all elements
        return -1;
    }
}

class NumArray {
