public class Codec {
    Map<String, String> shortToLong = new HashMap<>();
    Map<String, String> longToShort = new HashMap<>();
    String domain = "http://tinyurl.com/";
    String chars = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
    int counter = 0;

    // Encodes a URL to a shortened URL.
    public String encode(String longUrl) {
        if (longToShort.containsKey(longUrl)) {
            return longToShort.get(longUrl);
        }
        String shortUrl = domain + generateShortCode();
        longToShort.put(longUrl, shortUrl);
        shortToLong.put(shortUrl, longUrl);
        return shortUrl;
    }

    // Decodes a shortened URL to its original URL.
    public String decode(String shortUrl) {
        return shortToLong.get(shortUrl);
    }

    private String generateShortCode() {
        // Simple counter-based generation for demonstration
        // In a real system, use a more robust method like base62 conversion
        String code = "";
        int temp = counter;
        while(temp > 0) {
            code = chars.charAt(temp % 62) + code;
            temp /= 62;
        }
        counter++;
        // Ensure code is not empty if counter is 0
        if (code.isEmpty()) {
            code = String.valueOf(chars.charAt(0));
        }
        return code;
    }
}

