import java.util.Arrays;

class Solution {
    public boolean checkInclusion(String s1, String s2) {
        if (s1.length() > s2.length()) {
            return false;
        }

        int[] s1Freq = new int[26];
        int[] windowFreq = new int[26];

        // Initialize frequencies for s1 and the first window of s2
        for (int i = 0; i < s1.length(); i++) {
            s1Freq[s1.charAt(i) - 'a']++;
            windowFreq[s2.charAt(i) - 'a']++;
        }

        // Check the first window
        if (Arrays.equals(s1Freq, windowFreq)) {
            return true;
        }

        // Slide the window
        for (int i = s1.length(); i < s2.length(); i++) {
            // Add new character entering the window
            windowFreq[s2.charAt(i) - 'a']++;
            // Remove character leaving the window
            windowFreq[s2.charAt(i - s1.length()) - 'a']--;

            // Check if frequencies match
            if (Arrays.equals(s1Freq, windowFreq)) {
                return true;
            }
        }

        return false;
    }
}

import java.util.Stack;

class Solution {
    public int calPoints(String[] ops) {
        Stack<Integer> scores = new Stack<>();
        int totalSum = 0;

        for (String op : ops) {
            if (op.equals("C")) {
                if (!scores.isEmpty()) {
                    scores.pop();
                }
            } else if (op.equals("D")) {
                if (!scores.isEmpty()) {
                    scores.push(scores.peek() * 2);
                }
            } else if (op.equals("+")) {
                if (scores.size() >= 2) {
                    int last = scores.pop();
                    int secondLast = scores.peek();
                    scores.push(last); // Push the last score back
                    scores.push(last + secondLast);
                }
            } else {
                scores.push(Integer.parseInt(op));
            }
        }

        // Calculate the sum of remaining scores
        while (!scores.isEmpty()) {
            totalSum += scores.pop();
        }
        return totalSum;
    }
}

/**
 * Definition for singly-linked list.
 * public class ListNode {
 *     int val;
 *     ListNode next;
 *     ListNode() {}
 *     ListNode(int val) { this.val = val; }
 *     ListNode(int val, ListNode next) { this.val = val; this.next = next; }
 * }
 */
class Solution {
    public void reorderList(ListNode head) {
        if (head == null || head.next == null) {
            return;
        }

        // 1. Find the middle node
        ListNode slow = head;
        ListNode fast = head;
        while (fast != null && fast.next != null) {
            slow = slow.next;
            fast = fast.next.next;
        }

        // 2. Reverse the second half
        ListNode secondHalfHead = reverseList(slow);

        // 3. Split the list (optional, handled by merge logic)
        // slow is the start of the second half, we need to break the link from the first half
        // This is implicitly handled by the merge logic if we are careful
        // Let's find the node *before* slow to break the link
        ListNode prevSlow = head;
        while (prevSlow.next != slow) {
             prevSlow = prevSlow.next;
        }
        prevSlow.next = null; // Break the list

        // 4. Merge the two halves
        ListNode firstHalfHead = head;
        ListNode p1 = firstHalfHead;
        ListNode p2 = secondHalfHead;

        while (p2 != null) { // Continue as long as the second half has nodes
            ListNode nextP1 = p1.next;
            ListNode nextP2 = p2.next;

            p1.next = p2;
            p2.next = nextP1;

            p1 = nextP1;
            p2 = nextP2;
        }
    }

    // Helper function to reverse a linked list
    private ListNode reverseList(ListNode head) {
        ListNode prev = null;
        ListNode current = head;
        while (current != null) {
            ListNode nextTemp = current.next;
            current.next = prev;
            prev = current;
            current = nextTemp;
        }
        return prev;
    }
}

class Solution {
    int goodNodesCount = 0;

    public int goodNodes(TreeNode root) {
        // Start DFS with root and smallest possible max_so_far
        dfs(root, Integer.MIN_VALUE);
        return goodNodesCount;
    }

    private void dfs(TreeNode node, int maxSoFar) {
        // Base case: If node is null, stop recursion
        if (node == null) {
            return;
        }

        // Check if current node is a "good node"
        if (node.val >= maxSoFar) {
            goodNodesCount++;
        }

        // Update maxSoFar for children's recursive calls
        int newMaxSoFar = Math.max(maxSoFar, node.val);

        // Recurse for left and right children
        dfs(node.left, newMaxSoFar);
        dfs(node.right, newMaxSoFar);
    }
}

class Solution {
    List<List<String>> result = new ArrayList<>();

    public List<List<String>> partition(String s) {
        backtrack(s, 0, new ArrayList<>());
        return result;
    }

    private void backtrack(String s, int start, List<String> currentPartition) {
        // Base case: If we've processed the entire string
        if (start == s.length()) {
            result.add(new ArrayList<>(currentPartition)); // Add a copy of the current partition
            return;
        }

        // Explore all possible partitions from the current 'start' index
        for (int i = start; i < s.length(); i++) {
            // Check if the substring from 'start' to 'i' is a palindrome
            if (isPalindrome(s, start, i)) {
                String sub = s.substring(start, i + 1);
                currentPartition.add(sub); // Choose: Add the palindrome
                backtrack(s, i + 1, currentPartition); // Explore: Recurse with the next starting point
                currentPartition.remove(currentPartition.size() - 1); // Unchoose: Backtrack
            }
        }
    }

    // Helper function to check if a substring is a palindrome
    private boolean isPalindrome(String s, int left, int right) {
        while (left < right) {
            if (s.charAt(left) != s.charAt(right)) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }
}

class Solution {
    // Map digits to letters
    private String[] digitToLetters = {
        "",     // 0
        "",     // 1
        "abc",  // 2
        "def",  // 3
        "ghi",  // 4
        "jkl",  // 5
        "mno",  // 6
        "pqrs", // 7
        "tuv",  // 8
        "wxyz"  // 9
    };

    private List<String> result;
    private String digits;

    public List<String> letterCombinations(String digits) {
        result = new ArrayList<>();
        if (digits == null || digits.length() == 0) {
            return result; // Handle empty input
        }
        this.digits = digits;
        backtrack(0, new StringBuilder()); // Start backtracking from index 0
        return result;
    }

    private void backtrack(int index, StringBuilder currentCombination) {
        // Base case: If current combination is complete
        if (index == digits.length()) {
            result.add(currentCombination.toString());
            return;
        }

        // Get the current digit and its corresponding letters
        char digitChar = digits.charAt(index);
        String letters = digitToLetters[digitChar - '0'];

        // Iterate through letters and recurse
        for (char letter : letters.toCharArray()) {
            currentCombination.append(letter); // Choose
            backtrack(index + 1, currentCombination); // Explore
            currentCombination.deleteCharAt(currentCombination.length() - 1); // Unchoose (backtrack)
        }
    }
}

class Solution {
    private int[][] grid;
    private boolean[][] visited;
    private int rows, cols;

    public int maxAreaOfIsland(int[][] grid) {
        this.grid = grid;
        rows = grid.length;
        cols = grid[0].length;
        visited = new boolean[rows][cols];
        int maxArea = 0;

        // Iterate through each cell in the grid
        for (int r = 0; r < rows; r++) {
            for (int c = 0; c < cols; c++) {
                // If it's land and not visited, start a DFS/BFS
                if (grid[r][c] == 1 && !visited[r][c]) {
                    maxArea = Math.max(maxArea, dfs(r, c)); // Calculate area and update max
                }
            }
        }
        return maxArea;
    }

    // DFS helper function to calculate island area
    private int dfs(int r, int c) {
        // Base cases for DFS: out of bounds, water, or already visited
        if (r < 0 || r >= rows || c < 0 || c >= cols || grid[r][c] == 0 || visited[r][c]) {
            return 0;
        }

        visited[r][c] = true; // Mark current cell as visited
        int currentArea = 1; // Count current cell

        // Explore neighbors (up, down, left, right)
        currentArea += dfs(r + 1, c); // Down
        currentArea += dfs(r - 1, c); // Up
        currentArea += dfs(r, c + 1); // Right
        currentArea += dfs(r, c - 1); // Left

        return currentArea;
    }
}

class Solution {
    int[][] directions = {{0, 1}, {0, -1}, {1, 0}, {-1, 0}}; // Standard 4-directional moves
    int m, n; // Grid dimensions

    public List<List<Integer>> pacificAtlantic(int[][] heights) {
        List<List<Integer>> result = new ArrayList<>();
        if (heights == null || heights.length == 0 || heights[0].length == 0) {
            return result; // Handle empty or invalid grid
        }

        m = heights.length;
        n = heights[0].length;

        // Two boolean matrices to track reachability from each ocean
        boolean[][] pacificReachable = new boolean[m][n];
        boolean[][] atlanticReachable = new boolean[m][n];

        // Start DFS from all cells on the Pacific border (top row and left column)
        for (int r = 0; r < m; r++) {
            dfs(heights, r, 0, pacificReachable, Integer.MIN_VALUE); // Leftmost column
        }
        for (int c = 0; c < n; c++) {
            dfs(heights, 0, c, pacificReachable, Integer.MIN_VALUE); // Topmost row
        }

        // Start DFS from all cells on the Atlantic border (bottom row and right column)
        for (int r = 0; r < m; r++) {
            dfs(heights, r, n - 1, atlanticReachable, Integer.MIN_VALUE); // Rightmost column
        }
        for (int c = 0; c < n; c++) {
            dfs(heights, m - 1, c, atlanticReachable, Integer.MIN_VALUE); // Bottommost row
        }

        // Iterate through the grid to find cells reachable by both oceans
        for (int r = 0; r < m; r++) {
            for (int c = 0; c < n; c++) {
                if (pacificReachable[r][c] && atlanticReachable[r][c]) {
                    result.add(Arrays.asList(r, c)); // Add to result if reachable by both
                }
            }
        }
        return result;
    }

    // Helper DFS function to mark all cells reachable from a starting point
    private void dfs(int[][] heights, int r, int c, boolean[][] reachable, int prevHeight) {
        // Base cases: out of bounds, already visited, or current cell is lower than previous (cannot flow upwards)
        if (r < 0 || r >= m || c < 0 || c >= n || reachable[r][c] || heights[r][c] < prevHeight) {
            return;
        }

        reachable[r][c] = true; // Mark current cell as reachable

        // Recursively explore all 4 neighbors
        for (int[] dir : directions) {
            dfs(heights, r + dir[0], c + dir[1], reachable, heights[r][c]);
        }
    }
}

class Solution {
    int m, n;
    char[][] board;
    int[][] directions = {{0, 1}, {0, -1}, {1, 0}, {-1, 0}}; // Standard 4-directional moves

    public void solve(char[][] board) {
        if (board == null || board.length == 0 || board[0].length == 0) {
            return; // Handle empty or invalid board
        }

        this.board = board;
        m = board.length;
        n = board[0].length;

        // No 'O' can be surrounded on boards smaller than 3x3
        if (m < 3 || n < 3) {
            return;
        }

        // Step 1: DFS from 'O's on the top and bottom borders
        for (int c = 0; c < n; c++) {
            if (board[0][c] == 'O') {
                dfs(0, c);
            }
            if (board[m - 1][c] == 'O') {
                dfs(m - 1, c);
            }
        }

        // Step 2: DFS from 'O's on the left and right borders
        for (int r = 0; r < m; r++) {
            if (board[r][0] == 'O') {
                dfs(r, 0);
            }
            if (board[r][n - 1] == 'O') {
                dfs(r, n - 1);
            }
        }

        // Step 3: Iterate through the board to flip 'O's and revert marked cells
        for (int r = 0; r < m; r++) {
            for (int c = 0; c < n; c++) {
                if (board[r][c] == 'O') {
                    board[r][c] = 'X'; // Surrounded 'O's become 'X'
                } else if (board[r][c] == '#') {
                    board[r][c] = 'O'; // Marked 'O's revert to 'O'
                }
            }
        }
    }

    // Helper DFS function to mark connected 'O's as safe
    private void dfs(int r, int c) {
        // Base cases: out of bounds or not an 'O' (already visited or 'X')
        if (r < 0 || r >= m || c < 0 || c >= n || board[r][c] != 'O') {
            return;
        }

        board[r][c] = '#'; // Mark as visited/safe with a temporary character

        // Explore neighbors
        for (int[] dir : directions) {
            dfs(r + dir[0], c + dir[1]);
        }
    }
}

class Solution {
    class UnionFind {
        private int[] parent;
        private int[] rank;

        public UnionFind(int n) {
            parent = new int[n + 1]; // 1-indexed nodes
            rank = new int[n + 1];
            for (int i = 1; i <= n; i++) {
                parent[i] = i;
                rank[i] = 1;
            }
        }

        public int find(int i) {
            if (parent[i] == i) {
                return i;
            }
            return parent[i] = find(parent[i]); // Path compression
        }

        public boolean union(int i, int j) {
            int rootI = find(i);
            int rootJ = find(j);

            if (rootI != rootJ) {
                // Union by rank
                if (rank[rootI] < rank[rootJ]) {
                    parent[rootI] = rootJ;
                } else if (rank[rootJ] < rank[rootI]) {
                    parent[rootJ] = rootI;
                } else {
                    parent[rootJ] = rootI;
                    rank[rootI]++;
                }
                return true; // Successfully united
            }
            return false; // Already in the same set, cycle detected
        }
    }

    public int[] findRedundantConnection(int[][] edges) {
        int n = edges.length; // Number of nodes is equal to number of edges in this problem
        UnionFind uf = new UnionFind(n);

        for (int[] edge : edges) {
            int u = edge[0];
            int v = edge[1];
            if (!uf.union(u, v)) { // If union returns false, a cycle was detected
                return edge;
            }
        }
        return new int[0]; // Should not reach here based on problem constraints
    }
}

class Solution {
    int count = 0;

    public int countSubstrings(String s) {
        if (s == null || s.length() == 0) {
            return 0;
        }
        for (int i = 0; i < s.length(); i++) {
            // Odd length palindromes, centered at i
            expandAroundCenter(s, i, i);
            // Even length palindromes, centered between i and i+1
            expandAroundCenter(s, i, i + 1);
        }
        return count;
    }

    private void expandAroundCenter(String s, int left, int right) {
        while (left >= 0 && right < s.length() && s.charAt(left) == s.charAt(right)) {
            count++;
            left--;
            right++;
        }
    }
}

class Solution {
    public int maxProfit(int[] prices) {
        if (prices == null || prices.length < 2) {
            return 0;
        }

        int n = prices.length;
        // dp[i][0]: max profit if not holding stock on day i
        // dp[i][1]: max profit if holding stock on day i
        int[][] dp = new int[n][2];

        // Base case for day 0
        dp[0][0] = 0;
        dp[0][1] = -prices[0];

        // Iterate from day 1
        for (int i = 1; i < n; i++) {
            // Max profit if not holding stock on day i
            // Option 1: Was not holding yesterday, and do nothing today
            // Option 2: Was holding yesterday, and sold today
            dp[i][0] = Math.max(dp[i-1][0], dp[i-1][1] + prices[i]);

            // Max profit if holding stock on day i
            // Option 1: Was holding yesterday, and do nothing today
            // Option 2: Bought today. This means we must have been in a "not holding" state
            //           two days ago (dp[i-2][0]) to satisfy the cooldown.
            //           If i < 2, it means we bought on day 0 or day 1 without a prior sell,
            //           so the profit before buying is 0.
            int profitBeforeBuy = (i >= 2) ? dp[i-2][0] : 0;
            dp[i][1] = Math.max(dp[i-1][1], profitBeforeBuy - prices[i]);
        }

        // The maximum profit will be when we are not holding stock on the last day
        return dp[n-1][0];
    }
}

class Solution {
    public int change(int amount, int[] coins) {
        // dp[i][j] will be the number of ways to make amount j using the first i coins
        // coins array is 0-indexed, so coins[i-1] refers to the i-th coin
        int[][] dp = new int[coins.length + 1][amount + 1];

        // Base case: There is one way to make amount 0 (by using no coins)
        for (int i = 0; i <= coins.length; i++) {
            dp[i][0] = 1;
        }

        // Iterate through each coin
        for (int i = 1; i <= coins.length; i++) {
            // Iterate through each amount
            for (int j = 1; j <= amount; j++) {
                // Option 1: Do not use the current coin (coins[i-1])
                dp[i][j] = dp[i-1][j];

                // Option 2: Use the current coin (coins[i-1])
                // If the current amount j is greater than or equal to the coin's value
                if (j >= coins[i-1]) {
                    // Add the number of ways to make the remaining amount (j - coins[i-1])
                    // using the current coin (and previous coins). We use dp[i][j - coins[i-1]]
                    // because we can use the current coin multiple times.
                    dp[i][j] += dp[i][j - coins[i-1]];
                }
            }
        }

        // The result is the number of ways to make 'amount' using all 'coins'
        return dp[coins.length][amount];
    }
}

class Solution {
    public boolean isInterleave(String s1, String s2, String s3) {
        // Check total length mismatch
        if (s1.length() + s2.length() != s3.length()) {
            return false;
        }

        // dp[i][j] means s1[0...i-1] and s2[0...j-1] can interleave to form s3[0...i+j-1]
        boolean[][] dp = new boolean[s1.length() + 1][s2.length() + 1];

        // Base case: empty s1 and empty s2 can form empty s3
        dp[0][0] = true;

        // Fill first row (s2 is empty)
        for (int i = 1; i <= s1.length(); i++) {
            if (s1.charAt(i - 1) == s3.charAt(i - 1) && dp[i - 1][0]) {
                dp[i][0] = true;
            }
        }

        // Fill first column (s1 is empty)
        for (int j = 1; j <= s2.length(); j++) {
            if (s2.charAt(j - 1) == s3.charAt(j - 1) && dp[0][j - 1]) {
                dp[0][j] = true;
            }
        }

        // Fill the rest of the DP table
        for (int i = 1; i <= s1.length(); i++) {
            for (int j = 1; j <= s2.length(); j++) {
                // Option 1: Take from s1
                boolean fromS1 = (s1.charAt(i - 1) == s3.charAt(i + j - 1)) && dp[i - 1][j];
                // Option 2: Take from s2
                boolean fromS2 = (s2.charAt(j - 1) == s3.charAt(i + j - 1)) && dp[i][j - 1];

                dp[i][j] = fromS1 || fromS2;
            }
        }

        return dp[s1.length()][s2.length()];
    }
}

class Solution {
    public int canCompleteCircuit(int[] gas, int[] cost) {
        int totalGas = 0;
        int totalCost = 0;
        int currentTank = 0;
        int startStation = 0;

        // Calculate total gas and total cost
        for (int i = 0; i < gas.length; i++) {
            totalGas += gas[i];
            totalCost += cost[i];
        }

        // If total gas is less than total cost, it's impossible to complete the circuit
        if (totalGas < totalCost) {
            return -1;
        }

        // Iterate through stations to find a potential starting point
        for (int i = 0; i < gas.length; i++) {
            currentTank += gas[i] - cost[i]; // Net change in gas at station i

            // If current tank drops below zero, this startStation is invalid.
            // Try the next station as a potential start.
            if (currentTank < 0) {
                startStation = i + 1;
                currentTank = 0; // Reset tank for the new potential start
            }
        }

        // If a solution exists (which it must if totalGas >= totalCost),
        // startStation will hold the correct index.
        return startStation;
    }
}

class Solution {
    public boolean isNStraightHand(int[] hand, int groupSize) {
        if (hand.length % groupSize != 0) {
            return false; // Cannot form groups if total cards not divisible by groupSize
        }
        Map<Integer, Integer> counts = new TreeMap<>(); // TreeMap keeps keys sorted
        for (int card : hand) {
            counts.put(card, counts.getOrDefault(card, 0) + 1);
        }

        for (int startCard : counts.keySet()) { // Iterate through sorted unique cards
            int count = counts.get(startCard);
            if (count > 0) { // If this card still needs to be grouped
                for (int i = 0; i < groupSize; i++) {
                    int currentCard = startCard + i;
                    // Check if currentCard exists and has enough count
                    if (counts.getOrDefault(currentCard, 0) < count) {
                        return false; // Not enough consecutive cards for this straight
                    }
                    // Decrement counts for all cards in the straight
                    counts.put(currentCard, counts.get(currentCard) - count);
                }
            }
        }
        return true; // All cards successfully grouped
    }
}

class Solution {
    public boolean checkValidString(String s) {
        int minOpen = 0; // Minimum possible open parentheses count
        int maxOpen = 0; // Maximum possible open parentheses count

        for (char c : s.toCharArray()) {
            if (c == '(') {
                minOpen++;
                maxOpen++;
            } else if (c == ')') {
                minOpen--;
                maxOpen--;
            } else { // c == '*'
                minOpen--; // Treat '*' as ')' to minimize open count
                maxOpen++; // Treat '*' as '(' to maximize open count
            }

            // If maxOpen ever drops below 0, it means we have too many ')'
            // even if all '*' are used as '(', so it's invalid.
            if (maxOpen < 0) {
                return false;
            }

            // minOpen cannot be negative; if it is, it means we had to use '*' as ')'
            // or empty to balance, effectively making minOpen 0.
            minOpen = Math.max(0, minOpen);
        }

        // At the end, if minOpen is 0, it means we can balance all parentheses.
        return minOpen == 0;
    }
}

class Solution {
    public List<Integer> spiralOrder(int[][] matrix) {
        List<Integer> result = new ArrayList<>();
        if (matrix == null || matrix.length == 0 || matrix[0].length == 0) {
            return result; // Handle empty or invalid matrix
        }

        int m = matrix.length;
        int n = matrix[0].length;

        int top = 0;
        int bottom = m - 1;
        int left = 0;
        int right = n - 1;

        while (top <= bottom && left <= right) {
            // Traverse right (top row)
            for (int col = left; col <= right; col++) {
                result.add(matrix[top][col]);
            }
            top++; // Move top boundary down

            // Traverse down (rightmost column)
            for (int row = top; row <= bottom; row++) {
                result.add(matrix[row][right]);
            }
            right--; // Move right boundary left

            // Check if there are still rows to traverse (e.g., for single row matrix)
            if (top <= bottom) {
                // Traverse left (bottom row)
                for (int col = right; col >= left; col--) {
                    result.add(matrix[bottom][col]);
                }
                bottom--; // Move bottom boundary up
            }

            // Check if there are still columns to traverse (e.g., for single column matrix)
            if (left <= right) {
                // Traverse up (leftmost column)
                for (int row = bottom; row >= top; row--) {
                    result.add(matrix[row][left]);
                }
                left++; // Move left boundary right
            }
        }
        return result;
    }
}

class Solution {
    public String multiply(String num1, String num2) {
        if (num1.equals("0") || num2.equals("0")) {
            return "0"; // Handle cases where one of the numbers is zero
        }

        int m = num1.length();
        int n = num2.length();
        int[] pos = new int[m + n]; // Array to store intermediate products and carries

        // Iterate through num1 from right to left
        for (int i = m - 1; i >= 0; i--) {
            int digit1 = num1.charAt(i) - '0';

            // Iterate through num2 from right to left
            for (int j = n - 1; j >= 0; j--) {
                int digit2 = num2.charAt(j) - '0';

                // Calculate product and sum with existing value at pos[i+j+1]
                int product = digit1 * digit2;
                int sum = product + pos[i + j + 1];

                // Place the unit digit of sum at pos[i+j+1]
                pos[i + j + 1] = sum % 10;
                // Add the carry to pos[i+j]
                pos[i + j] += sum / 10;
            }
        }

        // Build the result string from the pos array
        StringBuilder sb = new StringBuilder();
        for (int p : pos) {
            // Skip leading zeros, unless it's the only digit
            if (!(sb.length() == 0 && p == 0)) {
                sb.append(p);
            }
        }

        // If sb is empty (e.g., result was "0" but handled by initial check), return "0"
        return sb.length() == 0 ? "0" : sb.toString();
    }
}

class Solution {
    public List<Integer> findDisappearedNumbers(int[] nums) {
        // Step 1 & 2: Mark numbers present by negating values at corresponding indices
        for (int i = 0; i < nums.length; i++) {
            int index = Math.abs(nums[i]) - 1; // Get the 0-based index for the current number
            if (nums[index] > 0) { // If the number at this index hasn't been marked yet
                nums[index] = -nums[index]; // Mark it as seen by negating its value
            }
        }

        // Step 3 & 4: Collect disappeared numbers
        List<Integer> result = new ArrayList<>();
        for (int i = 0; i < nums.length; i++) {
            if (nums[i] > 0) { // If the number at this index is positive, it means (i+1) was never seen
                result.add(i + 1); // Add the disappeared number (index + 1) to the result
            }
        }
        return result;
    }
}

class Solution {
    public int maxNumberOfBalloons(String text) {
        // Step 1: Initialize a frequency map for characters 'a' through 'z'
        int[] charCounts = new int[26]; // Array to store frequency of each character

        // Step 2: Populate the frequency map from the input text
        for (char c : text.toCharArray()) {
            charCounts[c - 'a']++;
        }

        // Step 3: Get counts for characters required for "balloon"
        int countB = charCounts['b' - 'a'];
        int countA = charCounts['a' - 'a'];
        int countL = charCounts['l' - 'a'];
        int countO = charCounts['o' - 'a'];
        int countN = charCounts['n' - 'a'];

        // Step 4: Adjust counts for 'l' and 'o' as they appear twice
        countL /= 2;
        countO /= 2;

        // Step 5: Find the minimum of these adjusted counts
        int maxBalloons = Math.min(countB, Math.min(countA, Math.min(countL, Math.min(countO, countN))));

        return maxBalloons;
    }
}

class Solution {
    public boolean wordPattern(String pattern, String s) {
        String[] words = s.split(" "); // Step 1: Split the sentence into words

        if (pattern.length() != words.length) { // Step 2: Check length consistency
            return false;
        }

        Map<Character, String> charToWord = new HashMap<>(); // Step 3: Map for char -> word
        Map<String, Character> wordToChar = new HashMap<>(); // Step 3: Map for word -> char

        for (int i = 0; i < pattern.length(); i++) { // Step 4: Iterate and validate mappings
            char pChar = pattern.charAt(i);
            String sWord = words[i];

            // Check charToWord mapping
            if (charToWord.containsKey(pChar)) {
                if (!charToWord.get(pChar).equals(sWord)) {
                    return false; // Step 5: Conflict found
                }
            } else {
                charToWord.put(pChar, sWord); // Add new mapping
            }

            // Check wordToChar mapping
            if (wordToChar.containsKey(sWord)) {
                if (!wordToChar.get(sWord).equals(pChar)) {
                    return false; // Step 5: Conflict found
                }
            } else {
                wordToChar.put(sWord, pChar); // Add new mapping
            }
        }

        return true; // Step 6: All mappings are consistent
    }
}

class MyHashSet {
    private static final int BUCKET_SIZE = 1000; // Choose a suitable prime number for buckets
    private List<Integer>[] buckets; // Array of linked lists (or ArrayLists)

    /** Initialize your data structure here. */
    public MyHashSet() {
        buckets = new LinkedList[BUCKET_SIZE]; // Step 1: Initialize array of LinkedLists
        for (int i = 0; i < BUCKET_SIZE; i++) {
            buckets[i] = new LinkedList<>(); // Initialize each bucket
        }
    }

    // Step 2: Simple hash function
    private int getBucketIndex(int key) {
        return key % BUCKET_SIZE;
    }

    public void add(int key) { // Step 3: Implement add(key)
        int index = getBucketIndex(key);
        if (!buckets[index].contains(key)) {
            buckets[index].add(key);
        }
    }

    public void remove(int key) { // Step 4: Implement remove(key)
        int index = getBucketIndex(key);
        // Use Integer.valueOf to remove by object, not index
        buckets[index].remove(Integer.valueOf(key)); 
    }

    /** Returns true if this set contains the specified element */
    public boolean contains(int key) { // Step 5: Implement contains(key)
        int index = getBucketIndex(key);
        return buckets[index].contains(key);
    }
}

class MyHashMap {
    private static final int BUCKET_SIZE = 1000; // Or a prime number
    private LinkedList<Entry>[] buckets;

    private static class Entry {
        int key;
        int value;
        Entry(int key, int value) {
            this.key = key;
            this.value = value;
        }
    }

    public MyHashMap() {
        buckets = new LinkedList[BUCKET_SIZE];
        for (int i = 0; i < BUCKET_SIZE; i++) {
            buckets[i] = new LinkedList<>();
        }
    }

    private int hash(int key) {
        return key % BUCKET_SIZE;
    }

    public void put(int key, int value) {
        int bucketIndex = hash(key);
        LinkedList<Entry> bucket = buckets[bucketIndex];
        for (Entry entry : bucket) {
            if (entry.key == key) {
                entry.value = value; // Update existing key
                return;
            }
        }
        bucket.add(new Entry(key, value)); // Add new key-value pair
    }

    public int get(int key) {
        int bucketIndex = hash(key);
        LinkedList<Entry> bucket = buckets[bucketIndex];
        for (Entry entry : bucket) {
            if (entry.key == key) {
                return entry.value;
            }
        }
        return -1; // Key not found
    }

    public void remove(int key) {
        int bucketIndex = hash(key);
        LinkedList<Entry> bucket = buckets[bucketIndex];
        Entry toRemove = null;
        for (Entry entry : bucket) {
            if (entry.key == key) {
                toRemove = entry;
                break;
            }
        }
        if (toRemove != null) {
            bucket.remove(toRemove);
        }
    }
}

class Solution {
    public int[] sortArray(int[] nums) {
        if (nums == null || nums.length <= 1) {
            return nums;
        }
        mergeSort(nums, 0, nums.length - 1);
        return nums;
    }

    private void mergeSort(int[] nums, int left, int right) {
        if (left < right) {
            int mid = left + (right - left) / 2;
            mergeSort(nums, left, mid); // Sort left half
            mergeSort(nums, mid + 1, right); // Sort right half
            merge(nums, left, mid, right); // Merge sorted halves
        }
    }

    private void merge(int[] nums, int left, int mid, int right) {
        int[] temp = new int[right - left + 1];
        int i = left; // Pointer for left sub-array
        int j = mid + 1; // Pointer for right sub-array
        int k = 0; // Pointer for temp array

        // Merge elements into temp array
        while (i <= mid && j <= right) {
            if (nums[i] <= nums[j]) {
                temp[k++] = nums[i++];
            } else {
                temp[k++] = nums[j++];
            }
        }

        // Copy remaining elements from left sub-array
        while (i <= mid) {
            temp[k++] = nums[i++];
        }

        // Copy remaining elements from right sub-array
        while (j <= right) {
            temp[k++] = nums[j++];
        }

        // Copy merged elements back to original array
        for (int l = 0; l < temp.length; l++) {
            nums[left + l] = temp[l];
        }
    }
}

class Solution {
    public int leastBricks(List<List<Integer>> wall) {
        // Map to store the frequency of edge positions
        Map<Integer, Integer> edgeFrequencies = new HashMap<>();
        int maxFrequency = 0; // Stores the maximum frequency of any edge position

        // Iterate through each row of the wall
        for (List<Integer> row : wall) {
            int currentPosition = 0; // Cumulative sum for current row
            // Iterate through bricks in the current row, excluding the last brick
            // An edge at the very end of the wall doesn't count as a "gap" to pass through
            for (int i = 0; i < row.size() - 1; i++) {
                currentPosition += row.get(i); // Calculate the edge position
                // Increment frequency for this edge position
                edgeFrequencies.put(currentPosition, edgeFrequencies.getOrDefault(currentPosition, 0) + 1);
                // Update maxFrequency if current edge position has higher frequency
                maxFrequency = Math.max(maxFrequency, edgeFrequencies.get(currentPosition));
            }
        }

        // The minimum number of cuts is the total number of rows minus the maximum frequency of aligned edges
        return wall.size() - maxFrequency;
    }
}

class Solution {
    Map<Integer, Integer> memo = new HashMap<>(); // Stores LPS length for each bitmask
    String s; // Original string
    int n; // Length of the original string

    public int maxProduct(String s) {
        this.s = s;
        this.n = s.length();

        // Precompute LPS length for all possible subsequences (bitmasks)
        // The recursive calculateLPS will handle memoization for each mask
        for (int mask = 1; mask < (1 << n); mask++) {
            if (!memo.containsKey(mask)) {
                calculateLPS(mask);
            }
        }

        long maxProduct = 0; // Use long to prevent potential overflow for product

        // Iterate through all pairs of masks to find two disjoint palindromic subsequences
        for (int mask1 = 1; mask1 < (1 << n); mask1++) {
            for (int mask2 = 1; mask2 < (1 << n); mask2++) {
                // Check if the two masks (subsequences) are disjoint
                if ((mask1 & mask2) == 0) {
                    long currentProduct = (long)memo.get(mask1) * memo.get(mask2);
                    maxProduct = Math.max(maxProduct, currentProduct);
                }
            }
        }

        return (int) maxProduct;
    }

    // Helper function to calculate LPS for a given mask using recursion with memoization
    private int calculateLPS(int mask) {
        // Base case: If mask is empty, LPS is 0
        if (mask == 0) {
            return 0;
        }
        // If LPS for this mask is already computed, return it from memo
        if (memo.containsKey(mask)) {
            return memo.get(mask);
        }

        // Find the first and last characters (indices) included in the current mask
        int firstIdx = -1, lastIdx = -1;
        int countBits = 0;
        for (int i = 0; i < n; i++) {
            if ((mask & (1 << i)) != 0) {
                if (firstIdx == -1) {
                    firstIdx = i;
                }
                lastIdx = i;
                countBits++;
            }
        }

        // Base case: If only one character in the mask, LPS is 1
        if (countBits == 1) {
            memo.put(mask, 1);
            return 1;
        }

        int lpsLength;
        // If the characters at firstIdx and lastIdx match, they form part of the palindrome
        if (s.charAt(firstIdx) == s.charAt(lastIdx)) {
            // They contribute 2 to the LPS, plus the LPS of the inner subsequence
            int innerMask = mask ^ (1 << firstIdx) ^ (1 << lastIdx); // Mask excluding first and last
            lpsLength = 2 + calculateLPS(innerMask);
        } else {
            // If they don't match, take the maximum LPS by excluding either the first or the last character
            int maskWithoutFirst = mask ^ (1 << firstIdx);
            int maskWithoutLast = mask ^ (1 << lastIdx);
            lpsLength = Math.max(calculateLPS(maskWithoutFirst), calculateLPS(maskWithoutLast));
        }

        memo.put(mask, lpsLength);
        return lpsLength;
    }
}

class Solution {
    public List<Integer> findAnagrams(String s, String p) {
        List<Integer> result = new ArrayList<>();
        if (s.length() < p.length()) {
            return result;
        }

        Map<Character, Integer> pFreq = new HashMap<>();
        Map<Character, Integer> windowFreq = new HashMap<>();

        // Initialize frequency map for pattern p
        for (char c : p.toCharArray()) {
            pFreq.put(c, pFreq.getOrDefault(c, 0) + 1);
        }

        // Initialize the first window
        for (int i = 0; i < p.length(); i++) {
            char c = s.charAt(i);
            windowFreq.put(c, windowFreq.getOrDefault(c, 0) + 1);
        }

        // Compare the first window
        if (windowFreq.equals(pFreq)) {
            result.add(0);
        }

        // Slide the window
        for (int i = p.length(); i < s.length(); i++) {
            char charToRemove = s.charAt(i - p.length());
            char charToAdd = s.charAt(i);

            // Update window frequency map
            windowFreq.put(charToRemove, windowFreq.get(charToRemove) - 1);
            if (windowFreq.get(charToRemove) == 0) {
                windowFreq.remove(charToRemove);
            }
            windowFreq.put(charToAdd, windowFreq.getOrDefault(charToAdd, 0) + 1);

            // Compare current window
            if (windowFreq.equals(pFreq)) {
                result.add(i - p.length() + 1);
            }
        }

        return result;
    }
}

class Solution {
    public int strStr(String haystack, String needle) {
        if (needle.isEmpty()) {
            return 0;
        }
        if (haystack.length() < needle.length()) {
            return -1;
        }

        for (int i = 0; i <= haystack.length() - needle.length(); i++) {
            boolean match = true;
            for (int j = 0; j < needle.length(); j++) {
                if (haystack.charAt(i + j) != needle.charAt(j)) {
                    match = false;
                    break;
                }
            }
            if (match) {
                return i;
            }
        }

        return -1;
    }
}

class Solution {
    public boolean checkPossibility(int[] nums) {
        int violations = 0;
        for (int i = 1; i < nums.length; i++) {
            if (nums[i] < nums[i - 1]) {
                violations++;
                if (violations > 1) {
                    return false;
                }
                // Check if modifying nums[i-1] is possible
                if (i == 1 || nums[i] >= nums[i - 2]) {
                    nums[i - 1] = nums[i]; // Try modifying the previous element
                } else {
                    // Must modify nums[i], check if possible
                    nums[i] = nums[i - 1]; // Try modifying the current element
                }
            }
        }
        return true;
    }
}

class Solution {
    public boolean validPalindrome(String s) {
        int left = 0;
        int right = s.length() - 1;

        while (left < right) {
            if (s.charAt(left) != s.charAt(right)) {
                // Mismatch found, try removing left or right character
                return isPalindrome(s, left + 1, right) || isPalindrome(s, left, right - 1);
            }
            left++;
            right--;
        }
        // No mismatch found, it's already a palindrome
        return true;
    }

    private boolean isPalindrome(String s, int left, int right) {
        while (left < right) {
            if (s.charAt(left) != s.charAt(right)) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }
}

import java.util.Arrays;

class Solution {
    public int minimumDifference(int[] nums, int k) {
        if (k == 1) {
            return 0; // Difference is 0 if we only consider one score
        }
        Arrays.sort(nums);
        int minDifference = Integer.MAX_VALUE;

        // Slide a window of size k
        for (int i = 0; i <= nums.length - k; i++) {
            int currentLowest = nums[i];
            int currentHighest = nums[i + k - 1];
            int currentDifference = currentHighest - currentLowest;
            minDifference = Math.min(minDifference, currentDifference);
        }

        return minDifference;
    }
}

import java.util.HashSet;
import java.util.Set;

class Solution {
    public boolean containsNearbyDuplicate(int[] nums, int k) {
        Set<Integer> window = new HashSet<>();
        for (int i = 0; i < nums.length; i++) {
            // Check if the current element is already in the window
            if (!window.add(nums[i])) {
                return true; // Duplicate found within distance k
            }
            // Maintain the window size: remove the element that falls out of the window
            if (i >= k) {
                window.remove(nums[i - k]);
            }
        }
        // No duplicate found within distance k
        return false;
    }
}

import java.util.Arrays;

class Solution {
    public int maxFrequency(int[] nums, int k) {
        Arrays.sort(nums);
        int left = 0;
        long currentSum = 0; // Use long to prevent overflow
        int maxFrequency = 0;

        for (int right = 0; right < nums.length; right++) {
            currentSum += nums[right];

            // Calculate required increments for the current window
            // target sum = nums[right] * window_size
            // increments = target_sum - currentSum
            long requiredIncrements = (long)nums[right] * (right - left + 1) - currentSum;

            // If increments exceed k, shrink the window from the left
            while (requiredIncrements > k) {
                currentSum -= nums[left];
                left++;
                requiredIncrements = (long)nums[right] * (right - left + 1) - currentSum;
            }

            // Update the maximum frequency (window size)
            maxFrequency = Math.max(maxFrequency, right - left + 1);
        }

        return maxFrequency;
    }
}

/** 
 * Forward declaration of guess API.
 * @param  num   your guess
 * @return 	     -1 if num is higher than the picked number
 *			      1 if num is lower than the picked number
 *               0 if num is equal to the picked number
 * int guess(int num);
 */

public class Solution extends GuessGame {
    public int guessNumber(int n) {
        int low = 1;
        int high = n;

        while (low <= high) {
            // Calculate midpoint safely to avoid overflow
            int mid = low + (high - low) / 2;
            int result = guess(mid);

            if (result == 0) {
                // Found the number
                return mid;
            } else if (result == 1) {
                // Picked number is higher than mid, search in the right half
                low = mid + 1;
            } else { // result == -1
                // Picked number is lower than mid, search in the left half
                high = mid - 1;
            }
        }

        // Should not reach here if pick is within [1, n]
        return -1; 
    }
}

class Solution {
    public int[][] kClosest(int[][] points, int k) {
        // Max heap to store points based on distance
        PriorityQueue<int[]> maxHeap = new PriorityQueue<>((a, b) -> (b[0]*b[0] + b[1]*b[1]) - (a[0]*a[0] + a[1]*a[1]));

        for (int[] point : points) {
            maxHeap.offer(point);
            if (maxHeap.size() > k) {
                maxHeap.poll(); // Remove the farthest point
            }
        }

        int[][] result = new int[k][2];
        for (int i = 0; i < k; i++) {
            result[i] = maxHeap.poll();
        }
        return result;
    }
}

class Solution {
    public int leastInterval(char[] tasks, int n) {
        // Frequency map
        int[] freq = new int[26];
        for (char task : tasks) {
            freq[task - 'A']++;
        }

        // Max heap to store frequencies
        PriorityQueue<Integer> maxHeap = new PriorityQueue<>(Collections.reverseOrder());
        for (int count : freq) {
            if (count > 0) {
                maxHeap.offer(count);
            }
        }

        int time = 0;
        // Queue to store tasks in cooldown
        Queue<int[]> cooldownQueue = new LinkedList<>(); // {frequency, available_time}

        while (!maxHeap.isEmpty() || !cooldownQueue.isEmpty()) {
            time++;

            if (!maxHeap.isEmpty()) {
                int currentFreq = maxHeap.poll();
                currentFreq--;
                if (currentFreq > 0) {
                    cooldownQueue.offer(new int[]{currentFreq, time + n});
                }
            }

            // Check if tasks in cooldown are ready
            if (!cooldownQueue.isEmpty() && cooldownQueue.peek()[1] == time) {
                maxHeap.offer(cooldownQueue.poll()[0]);
            }
        }
        return time;
    }
}

class Solution {
    public int ladderLength(String beginWord, String endWord, List<String> wordList) {
        Set<String> wordSet = new HashSet<>(wordList);
        if (!wordSet.contains(endWord)) return 0;

        Queue<Pair<String, Integer>> queue = new LinkedList<>();
        queue.offer(new Pair<>(beginWord, 1));
        wordSet.remove(beginWord);

        while (!queue.isEmpty()) {
            Pair<String, Integer> current = queue.poll();
            String word = current.getKey();
            int level = current.getValue();

            if (word.equals(endWord)) return level;

            char[] charArray = word.toCharArray();
            for (int i = 0; i < charArray.length; i++) {
                char originalChar = charArray[i];
                for (char c = 'a'; c <= 'z'; c++) {
                    if (c == originalChar) continue;
                    charArray[i] = c;
                    String nextWord = new String(charArray);

                    if (wordSet.contains(nextWord)) {
                        queue.offer(new Pair<>(nextWord, level + 1));
                        wordSet.remove(nextWord);
                    }
                }
                charArray[i] = originalChar; // backtrack
            }
        }
        return 0;
    }
    // Assuming Pair class is available or defined
    class Pair<K, V> {
        K key;
        V value;
        public Pair(K key, V value) { this.key = key; this.value = value; }
        public K getKey() { return key; }
        public V getValue() { return value; }
    }
}

class Solution {
    Map<String, PriorityQueue<String>> adj = new HashMap<>();
    List<String> result = new LinkedList<>();

    public List<String> findItinerary(List<List<String>> tickets) {
        for (List<String> ticket : tickets) {
            adj.computeIfAbsent(ticket.get(0), k -> new PriorityQueue<>()).add(ticket.get(1));
        }
        dfs("JFK");
        Collections.reverse(result);
        return result;
    }

    private void dfs(String airport) {
        PriorityQueue<String> destinations = adj.get(airport);
        while (destinations != null && !destinations.isEmpty()) {
            String nextAirport = destinations.poll();
            dfs(nextAirport);
        }
        result.add(airport);
    }
}

class Solution {
    public int minCostConnectPoints(int[][] points) {
        int n = points.length;
        // Using Prim's Algorithm
        PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> a[0] - b[0]); // {cost, point_index}
        boolean[] visited = new boolean[n];
        int mstCost = 0;
        int edgesCount = 0;

        // Start with point 0
        pq.offer(new int[]{0, 0}); // Cost 0 to connect the first point to itself

        while (!pq.isEmpty() && edgesCount < n) {
            int[] current = pq.poll();
            int cost = current[0];
            int u = current[1];

            if (visited[u]) {
                continue;
            }

            visited[u] = true;
            mstCost += cost;
            edgesCount++;

            // Add edges to neighbors
            for (int v = 0; v < n; v++) {
                if (!visited[v]) {
                    int dist = Math.abs(points[u][0] - points[v][0]) + Math.abs(points[u][1] - points[v][1]);
                    pq.offer(new int[]{dist, v});
                }
            }
        }
        return mstCost;
    }
}

class Solution {
    public int swimInWater(int[][] grid) {
        int n = grid.length;
        PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> a[0] - b[0]); // {elevation, row, col}
        boolean[][] visited = new boolean[n][n];

        pq.offer(new int[]{grid[0][0], 0, 0});
        visited[0][0] = true;

        int[] dr = {-1, 1, 0, 0}; // Directions: up, down, left, right
        int[] dc = {0, 0, -1, 1};

        while (!pq.isEmpty()) {
            int[] current = pq.poll();
            int elevation = current[0];
            int r = current[1];
            int c = current[2];

            if (r == n - 1 && c == n - 1) {
                return elevation; // Reached the destination
            }

            for (int i = 0; i < 4; i++) {
                int nr = r + dr[i];
                int nc = c + dc[i];

                if (nr >= 0 && nr < n && nc >= 0 && nc < n && !visited[nr][nc]) {
                    visited[nr][nc] = true;
                    int nextElevation = Math.max(elevation, grid[nr][nc]);
                    pq.offer(new int[]{nextElevation, nr, nc});
                }
            }
        }
        return -1; // Should not happen in a valid grid
    }
}

class Solution {
    public int findTargetSumWays(int[] nums, int target) {
        int sum = 0;
        for (int num : nums) {
            sum += num;
        }

        // If target is unreachable or sum of elements is less than target
        if (Math.abs(target) > sum || (sum + target) % 2 != 0) {
            return 0;
        }

        int targetSum = (sum + target) / 2;
        int[] dp = new int[targetSum + 1];
        dp[0] = 1; // Base case: one way to achieve sum 0 (empty set)

        for (int num : nums) {
            for (int j = targetSum; j >= num; j--) {
                dp[j] += dp[j - num];
            }
        }

        return dp[targetSum];
    }
}

class Solution {
    public boolean isMatch(String s, String p) {
        int n = s.length();
        int m = p.length();
        boolean[][] dp = new boolean[n + 1][m + 1];

        dp[0][0] = true; // Empty string matches empty pattern

        // Handle patterns like a*, a*b*, etc. matching empty string
        for (int j = 1; j <= m; j++) {
            if (p.charAt(j - 1) == '*') {
                dp[0][j] = dp[0][j - 2];
            }
        }

        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= m; j++) {
                char sChar = s.charAt(i - 1);
                char pChar = p.charAt(j - 1);

                if (pChar == '.' || pChar == sChar) {
                    dp[i][j] = dp[i - 1][j - 1];
                } else if (pChar == '*') {
                    // Case 1: '*' matches zero preceding element
                    dp[i][j] = dp[i][j - 2];
                    // Case 2: '*' matches one or more preceding element
                    if (p.charAt(j - 2) == '.' || p.charAt(j - 2) == sChar) {
                        dp[i][j] = dp[i][j] || dp[i - 1][j];
                    }
                }
            }
        }

        return dp[n][m];
    }
}

class Solution {
    public boolean mergeTriplets(int[][] triplets, int[] target) {
        boolean foundTarget0 = false;
        boolean foundTarget1 = false;
        boolean foundTarget2 = false;

        for (int[] triplet : triplets) {
            // Check if the triplet is valid (elements are less than or equal to target elements)
            if (triplet[0] <= target[0] && triplet[1] <= target[1] && triplet[2] <= target[2]) {
                // Check if this triplet can contribute to forming the target
                if (triplet[0] == target[0]) {
                    foundTarget0 = true;
                }
                if (triplet[1] == target[1]) {
                    foundTarget1 = true;
                }
                if (triplet[2] == target[2]) {
                    foundTarget2 = true;
                }
            }
        }

        // Return true if all elements of the target can be formed by merging valid triplets
        return foundTarget0 && foundTarget1 && foundTarget2;
    }
}

import java.util.ArrayList;
