import java.util.Map;

class Solution {
    public List<Integer> partitionLabels(String s) {
        Map<Character, Integer> lastOccurrence = new HashMap<>();
        for (int i = 0; i < s.length(); i++) {
            lastOccurrence.put(s.charAt(i), i);
        }

        List<Integer> result = new ArrayList<>();
        int start = 0;
        int end = 0;

        for (int i = 0; i < s.length(); i++) {
            end = Math.max(end, lastOccurrence.get(s.charAt(i)));

            if (i == end) {
                result.add(end - start + 1);
                start = i + 1;
            }
        }

        return result;
    }
}

class Solution {
    public boolean isPalindrome(int x) {
        // Negative numbers are not palindromes
        if (x < 0) {
            return false;
        }
        // Numbers ending in 0 (except 0 itself) are not palindromes
        if (x != 0 && x % 10 == 0) {
            return false;
        }

        int revertedNumber = 0;
        int originalX = x; // Keep original for comparison if needed, or modify loop condition

        // Reverse the second half of the number
        while (x > revertedNumber) {
            int digit = x % 10;
            revertedNumber = revertedNumber * 10 + digit;
            x /= 10;
        }

        // When the length is an odd number, we can get rid of the middle digit by revertedNumber/10
        // For example when the input is 12321, at the end of the while loop we get x = 12, revertedNumber = 123,
        // since the middle digit doesn't matter in palidrome(it will always equal to itself), we can simply get rid of it.
        return x == revertedNumber || x == revertedNumber / 10;
    }
}

class Solution {
    public boolean isUgly(int n) {
        if (n <= 0) {
            return false;
        }

        // Divide by 2 until it's no longer divisible
        while (n % 2 == 0) {
            n /= 2;
        }

        // Divide by 3 until it's no longer divisible
        while (n % 3 == 0) {
            n /= 3;
        }

        // Divide by 5 until it's no longer divisible
        while (n % 5 == 0) {
            n /= 5;
        }

        // If the remaining number is 1, it's an ugly number
        return n == 1;
    }
}

class Solution {
    public int minSwaps(String s) {
        int balance = 0;
        int maxBalance = 0;
        for (char c : s.toCharArray()) {
            if (c == '[') {
                balance++;
            } else {
                balance--;
            }
            maxBalance = Math.max(maxBalance, -balance); // Track maximum imbalance (negative balance)
        }
        // If total '[' != total ']', it's impossible, but problem constraints usually guarantee this.
        // The number of swaps is ceil(maxBalance / 2.0)
        return (maxBalance + 1) / 2;
    }
}

import java.util.ArrayList;
import java.util.HashMap;
import java.util.Random;

class RandomizedSet {
    private HashMap<Integer, Integer> valToIndex;
    private ArrayList<Integer> list;
    private Random random;

    public RandomizedSet() {
        valToIndex = new HashMap<>();
        list = new ArrayList<>();
        random = new Random();
    }

    public boolean insert(int val) {
        if (valToIndex.containsKey(val)) {
            return false;
        }
        valToIndex.put(val, list.size());
        list.add(val);
        return true;
    }

    public boolean remove(int val) {
        if (!valToIndex.containsKey(val)) {
            return false;
        }
        int indexToRemove = valToIndex.get(val);
        int lastVal = list.get(list.size() - 1);

        // Swap the element to remove with the last element
        list.set(indexToRemove, lastVal);
        valToIndex.put(lastVal, indexToRemove);

        // Remove the last element
        list.remove(list.size() - 1);
        valToIndex.remove(val);
        return true;
    }

    public int getRandom() {
        int randomIndex = random.nextInt(list.size());
        return list.get(randomIndex);
    }
}

class Solution {
    public int signFunc(int[] nums) {
        int sign = 1; // 1 for positive, -1 for negative
        for (int num : nums) {
            if (num == 0) {
                return 0; // Product is zero if any element is zero
            }
            if (num < 0) {
                sign *= -1; // Flip the sign for each negative number
            }
            // Positive numbers don't change the sign
        }
        return sign;
    }
}
